/** Generated by tools/sync-catalog.mjs — do not edit by hand */
export const eventsCatalog = [{"id":"evt_welcome_club","tags":["social","y1"],"weight":10,"minTurn":0,"maxTurn":2,"title":"百团大战","body":"操场边上社团招新热火朝天，传单递到你手里像雪花。","choices":[{"text":"加入技术社团，周末泡活动室","effects":{"social":8,"skill":6,"pressure":4,"health":-3},"narrative":"你一头扎进了技术社团的活动室，从此周末不再是周末——是debug马拉松。学长递给你一块开发板，说'这个很简单，一周就能上手'。你信了。一个月后，你还在和那个'很简单'的模块斗智斗勇。不过说实话，当LED终于亮起来的那一刻，你觉得一切都值了。"},{"text":"只加一个轻松的兴趣社，保持边界","effects":{"social":4,"pressure":-2,"health":4},"narrative":"你选了一个摄影社，每周就出去拍拍照，顺便逛逛校园。社长说'我们社团的精髓就是佛系'，你深表赞同。别人在实验室通宵的时候，你在暗房里冲洗胶片，感觉自己活成了文艺片主角。合上日记本，今天谈不上轰轰烈烈，却也算稳稳向前挪了一小步。"},{"text":"不参加，把时间留给自学","effects":{"skill":5,"social":-4,"pressure":-3},"narrative":"你婉拒了所有传单，回到宿舍当起了「B站大学生」。'社团？我有最好的老师——弹幕。'你在评论区结识了几位志同道合的网友，虽然现实里的社交圈缩小了，但收藏夹已经涨到三位数。熄灯前你在脑子里复盘了一遍：今天还行，明天继续。"}]},{"id":"evt_calc_mid","tags":["academic","y1"],"weight":12,"minTurn":0,"maxTurn":3,"title":"高数期中前的夜","body":"证明题像绕口令，你在寝室开始怀疑人生。","choices":[{"text":"通宵肝完题库","effects":{"gpa":0.25,"health":-10,"pressure":12,"skill":3},"narrative":"凌晨三点，你的第三杯咖啡已经凉了。室友翻了个身，嘟囔了一句'别卷了'。你没有理会，继续和拉格朗日死磕。天亮的时候，你终于理解了中值定理的真谛——代价是第二天上课时你趴在桌上，口水浸湿了笔记本。但成绩出来那天，你觉得值了。你说不清具体收获了什么，心里却多了几分底气。"},{"text":"按节奏复习，保证睡眠","effects":{"gpa":0.12,"health":3,"pressure":-4},"narrative":"你制定了科学的复习计划：番茄钟25分钟，休息5分钟。晚上十点半准时合上书，戴上眼罩睡觉。室友惊讶地看着你：'明天就考试了你不慌？'你淡定地说：'睡眠也是复习的一部分。'事实证明你是对的——清醒的大脑比熬夜的大脑好用多了。这些事不大，却让大学生活更具体、更鲜活。"},{"text":"抱学霸大腿组队刷题","effects":{"gpa":0.18,"social":6,"money":-100,"pressure":2},"narrative":"你请学霸吃了顿饭，成功混入了他的刷题小组。学霸讲题的方式很独特：'这题你看，显然……'然后跳过了五步推导。你疯狂记笔记，虽然有一半没听懂，但至少记住了套路。考完试你请全组喝奶茶，算下来比报补习班便宜。你没有发朋友圈，但嘴角不自觉翘了一点。"}]},{"id":"evt_part_time","tags":["money","y1"],"weight":10,"minTurn":1,"maxTurn":5,"title":"兼职机会","body":"学长转来一个周末店员/家教的信息，时薪说得过去。","choices":[{"text":"接家教，多劳多得","effects":{"money":450,"gpa":-0.08,"pressure":6,"skill":2},"narrative":"你接了一个初中生家教，教数学。学生很聪明，就是不爱写作业。你使出了浑身解数：'你看这个二次函数，它像不像你爱豆的应援色？'没想到这招居然管用。虽然备课占用了你的复习时间，但看到学生成绩进步，你居然有了一种当老师的成就感。回到宿舍你突然觉得：嗯，今天也算没有白过。"},{"text":"只做校内勤工俭学，强度低","effects":{"money":200,"pressure":1},"narrative":"你在图书馆做勤工俭学，主要工作是整理书架和提醒同学不要吃东西。工作轻松，还能边值班边看书。唯一的烦恼是有同学把书乱放，你不得不像侦探一样把《量子力学》从言情小说区找回来。时间又翻过一页，你对接下来的日子多了几分期待。"},{"text":"不做，专注课业","effects":{"gpa":0.1,"skill":3},"narrative":"你决定不兼职，把时间全部投入学习。虽然钱包有点瘪，但你的知识储备在膨胀。你在心里安慰自己：'现在投资大脑，以后回报更大。'然后默默把购物车里的东西都删了。你在心里默默结算：时间没白花，人也踏实了些。"}]},{"id":"evt_roommate","tags":["life"],"weight":9,"title":"寝室矛盾","body":"熄灯后外放短视频、卫生轮值扯皮，让你很累。","choices":[{"text":"当面摊开聊，顺便订个值日表","effects":{"social":5,"pressure":-5,"health":3},"narrative":"你鼓起勇气，在寝室开了个'圆桌会议'。气氛一度很尴尬，但当你拿出打印好的值日表时，大家都笑了。'行吧，那就按这个来。'从此寝室卫生状况大幅改善，你们还顺便约定了'23点后戴耳机'的铁律。你发现，沟通真的能解决问题。事情做完的那一刻，你吐出一口气，像把一块小石头从心里搬走了。"},{"text":"冷处理，买耳塞眼罩自我消化","effects":{"pressure":8,"health":-4,"gpa":0.05},"narrative":"你默默下单了降噪耳塞和遮光眼罩，把自己武装成了一个'寝室忍者'。表面上你云淡风轻，实际上你每天都在心里默念'莫生气'。虽然问题没解决，但至少你把精力都发泄在了学习上，成绩反而涨了一点。你也没想太多，只是默默把这一格日子标成「还不错」。"},{"text":"申请换寝——手续麻烦但痛快","effects":{"pressure":-8,"money":-80,"social":-3},"narrative":"你跑了好几趟辅导员办公室，填了一堆表格，终于成功换了寝室。新室友都很安静，你终于可以在11点后享受宁静了。虽然搬寝室花了一些钱，和原来的室友关系也有点尴尬，但你每天晚上躺在床上，都觉得这个决定太正确了。夜风从窗缝钻进来，你伸了个懒腰，觉得身体和精神都轻了一点。"}]},{"id":"evt_english_cet","tags":["academic"],"weight":11,"minTurn":2,"maxTurn":6,"title":"四六级与口语","body":"报名费交了，你琢磨怎么分配时间和真题。","choices":[{"text":"每天高频刷题","effects":{"gpa":0.1,"skill":4,"pressure":5,"health":-2},"narrative":"你开启了'真题狂魔'模式，每天一套听力一套阅读。耳机里循环播放英语新闻，室友说你做梦都在说'Section A Directions...'。虽然过程痛苦，但当你发现能听懂美剧生肉的时候，你觉得一切都值了。你忽然明白，成长很多时候就是这样：不声不响，但方向清楚了一点。"},{"text":"报个小班课，跟着节奏走","effects":{"money":-280,"gpa":0.12,"skill":5,"pressure":2},"narrative":"你报了一个口碑不错的英语班，老师很幽默，把枯燥的语法讲成了脱口秀。'定语从句就像俄罗斯套娃，一个套一个。'你笑着笑着就学会了。虽然花了些钱，但有人带着学确实轻松不少。手机震了一下，是群里的梗图；你笑了一下，又关掉了屏幕。"},{"text":"裸考随缘，把时间给专业课","effects":{"gpa":0.08,"pressure":-6,"social":3},"narrative":"你决定裸考四六级，把时间都给了专业课。考试那天你心态超好：'反正也没复习，考多少都是赚。'结果居然还不错——你发现高中打下的底子还在。同学们都夸你心态好，你笑而不语，深藏功与名。这一页翻过去，下一件小事还在排队等你。"}]},{"id":"evt_crush","tags":["social"],"weight":8,"minTurn":0,"maxTurn":7,"title":"心动的选修课","body":"隔壁小组里有个让你总想多看两眼的人。","choices":[{"text":"大胆要微信，顺便约自习","effects":{"social":10,"pressure":6,"gpa":-0.05,"money":-60},"narrative":"你深吸一口气，在下课后走上前去：'同学，你的笔记能借我看看吗？'——这是你在心里排练了二十遍的开场白。对方笑了，说'好啊'。你们加了微信，约了自习。虽然自习的时候你有一半时间在偷看对方，但这段经历让你的大学生活多了一抹亮色。你把它写进待办里又划掉，像给今天盖了个「完成」的章。"},{"text":"默默关注，专注搞好小组作业","effects":{"gpa":0.15,"skill":4,"pressure":-2},"narrative":"你把这份心动转化为了学习的动力。每次小组讨论你都格外认真，做的PPT也格外精美。虽然你没有迈出那一步，但你们的小组作业拿了全班最高分。你在心里默默感谢了这份'暗恋的力量'。结果不算亮眼，但你坦然接受了这样的日常。"},{"text":"交给时间，先把课考到满意","effects":{"gpa":0.1,"health":4},"narrative":"你决定先专注于课程本身。'缘分这种事情，强求不来。'你对自己说。你把精力都投入到了学习中，每天规律作息，认真听课。至于那个让你心动的人——如果真的有缘，以后还会再见的。你给自己倒了杯水，像给今天画了个小小的句号。"}]},{"id":"evt_homesick","tags":["life"],"weight":8,"title":"想家电话","body":"妈妈问你习不习惯，你鼻子有点酸。","choices":[{"text":"周末回家充电","effects":{"health":10,"money":-120,"pressure":-8,"skill":-2},"narrative":"你买了回家的车票，一进门就闻到了熟悉的饭菜香。妈妈做了你最爱吃的菜，爸爸假装不经意地问你'学习怎么样'。在家待了两天，你像充满了电的电池。回学校的时候，背包里塞满了零食和妈妈的唠叨。窗外天色暗下去，你心里却亮了一点点。"},{"text":"视频聊聊，继续待学校推进计划","effects":{"pressure":-4,"skill":3},"narrative":"你和妈妈视频了一个小时，给她看了你的宿舍、你的课表、你养的绿植。妈妈在屏幕那头笑着说'长大了'。挂了电话，你虽然还是有点想家，但心里暖暖的。你打开笔记本，继续推进你的学习计划。你摸了摸口袋里的校园卡，觉得它跟今天的你很合拍。"},{"text":"约朋友打球转移注意力","effects":{"social":6,"health":5},"narrative":"你约了几个朋友去打球，在球场上挥汗如雨。打完球大家一起去食堂吃饭，聊着聊着你就忘了想家的事。朋友说：'想家很正常，但你不是一个人在这里。'你突然觉得，大学里的朋友也是家人。舍友问你为什么傻笑，你说没事——其实只是心情不错。"}]},{"id":"evt_project_course","tags":["skill","y2"],"weight":10,"minTurn":2,"maxTurn":7,"title":"大作业地狱周","body":"三门课同时截止：实验报告、原型、PPT。","choices":[{"text":"团队分工拉满，冲刺提交","effects":{"skill":10,"social":4,"pressure":14,"gpa":0.15,"health":-6},"narrative":"你们小组开启了'地狱模式'：有人负责写代码，有人负责写文档，有人负责做PPT。你在实验室连续待了三天，靠外卖和功能饮料续命。提交前五分钟，你们发现了一个bug，全员心跳加速。好在最后一刻修好了。提交后你们瘫在椅子上，相视一笑——这就是战友啊。"},{"text":"砍掉亮点，保证及格线上方","effects":{"pressure":-6,"gpa":-0.05,"health":4},"narrative":"你做了一个艰难的决定：砍掉那些花里胡哨的功能，只保留核心部分。'完成比完美重要。'你对自己说。虽然最终作品不够惊艳，但至少按时提交了，而且你没有因此熬夜到崩溃。你学会了取舍，这比任何技术都重要。夜深了，你摘下耳机，安静地结束了这一天。"},{"text":"请外包/买模板——不光彩但省力","effects":{"money":-200,"pressure":-10,"gpa":0.05,"skill":-4},"narrative":"你在网上找了人帮忙完成部分工作。虽然心里有点过意不去，但确实帮你度过了难关。提交的作品看起来还不错，只是答辩的时候你有点心虚。你在心里发誓：下次一定提前准备，不再走捷径了。镜中的你有些疲惫，眼神却很稳——日子还在正轨上。"}]},{"id":"evt_intern_apply","tags":["career","y3"],"weight":10,"minTurn":4,"maxTurn":7,"title":"暑期实习投递","body":"招聘软件红点炸了，你开始改简历和刷面经。","choices":[{"text":"海投 + 疯狂复盘面试","effects":{"skill":8,"pressure":10,"social":2,"money":-50},"narrative":"你开启了'海王模式'，一天投了二十家公司。面试安排得密密麻麻，你像一个面试机器，上午面完A公司下午赶B公司。虽然累到虚脱，但你的面试技巧突飞猛进。到后来，你已经能预判面试官要问什么了。你没写给谁的总结，却在心里默默点了点头。"},{"text":"精投少量目标公司","effects":{"skill":6,"pressure":4,"gpa":0.08},"narrative":"你仔细研究了五家目标公司，为每一家都定制了简历和求职信。面试的时候，你对公司的了解让面试官印象深刻。虽然投得少，但命中率高。你发现，质量比数量更重要。楼道里有脚步声远去，你的大学生活又多了一层回声。"},{"text":"先躺平等秋招再说了","effects":{"pressure":-8,"skill":-4,"health":5},"narrative":"你决定这个暑假先好好休息，等秋招再说。你在宿舍里追完了攒了一个学期的剧，每天睡到自然醒。虽然看着同学们都在实习有点慌，但你安慰自己：'人生是马拉松，不是百米冲刺。'——虽然你也不太确定这是智慧还是借口。你关上台灯，觉得今天像一张折好的纸，平平整整地收进抽屉里。"}]},{"id":"evt_research_lab","tags":["academic","y3"],"weight":9,"minTurn":4,"maxTurn":7,"title":"导师实验室邀请","body":"有课题组缺人手，晚周末可能没了，但能接触论文与实验。","choices":[{"text":"进组干活，冲保研/推荐信","effects":{"skill":12,"gpa":0.18,"pressure":12,"social":3,"health":-5},"narrative":"你正式加入了课题组，从此过上了'实验室是我家'的生活。跑数据、读论文、开组会，你的日程表被塞得满满当当。有一次你在实验室睡着了，醒来发现身上盖着师兄的外套。虽然累，但当你第一次在组会上做报告时，导师点了点头——那一刻你觉得一切都值了。风把窗帘轻轻吹动，你忽然觉得：日子就是这样一天天叠出来的。"},{"text":"远程轻量参与，控制投入","effects":{"skill":5,"gpa":0.08,"pressure":5},"narrative":"你和导师商量了一个折中方案：远程参与部分工作，不用天天泡实验室。你帮忙处理了一些数据，旁听了几次组会。虽然没有深入参与，但你对科研有了初步的了解，而且没有因此牺牲太多个人时间。合上日记本，今天谈不上轰轰烈烈，却也算稳稳向前挪了一小步。"},{"text":"婉拒，把时间留给实习","effects":{"money":150,"skill":4,"gpa":-0.04},"narrative":"你礼貌地婉拒了导师的邀请，决定把时间投入到实习中。'科研很好，但我想先看看业界是什么样的。'你在心里对自己说。虽然错过了一个科研机会，但你用这个时间找到了一份不错的实习。熄灯前你在脑子里复盘了一遍，觉得还行——明天继续。"}]},{"id":"evt_volunteer","tags":["social"],"weight":7,"title":"志愿活动","body":"学院组织支教/赛事志愿者，可以加综测分。","choices":[{"text":"报名参加，认识新朋友","effects":{"social":10,"pressure":3,"health":-2},"narrative":"你报名了支教活动，去了附近的一所小学。孩子们围着你叫'大学生老师'，你教他们画画、唱歌，还讲了你大学里的趣事。离开的时候，一个小女孩塞给你一张纸条：'老师，我以后也要上大学。'你差点没忍住眼泪。你说不清具体收获了什么，心里却多了几分底气。"},{"text":"只报名半天，留时间自习","effects":{"social":4,"gpa":0.06},"narrative":"你选择了半天的赛事志愿者，帮忙引导观众和分发物资。工作不算累，你还顺便看了一会儿比赛。下午你回到图书馆继续自习，感觉今天既做了有意义的事，又没有耽误学习。这些事不大，却让大学生活更具体、更鲜活。"},{"text":"不参加，把时间换钱或休息","effects":{"money":120,"health":4},"narrative":"你决定不参加志愿活动，用这个时间去做兼职。虽然少了综测加分，但你赚到了一些生活费，还好好休息了一下。你在心里盘算：'综测固然重要，但钱包和身体也很重要。'你没有发朋友圈，但嘴角不自觉翘了一点。"}]},{"id":"evt_peer_compare","tags":["life"],"weight":9,"minTurn":3,"maxTurn":7,"title":"朋友圈焦虑","body":"有人晒 offer、有人晒排名，你凌晨刷手机停不下。","choices":[{"text":"关掉社交软件，列自己的周计划","effects":{"pressure":-10,"skill":4,"health":5},"narrative":"你果断卸载了社交软件，拿出一张白纸开始列自己的周计划。'别人的生活是别人的，我只需要关注自己的进度。'你发现，当你专注于自己的目标时，焦虑自然就消失了。一周后，你的计划完成了一大半，成就感满满。回到宿舍你突然觉得：嗯，今天也算没有白过。"},{"text":"加倍内卷熬夜追赶","effects":{"gpa":0.1,"pressure":14,"health":-12},"narrative":"你被焦虑驱动着开始了疯狂的内卷模式。凌晨两点的图书馆，你发现居然还有不少人——原来大家都在卷。你苦笑了一下，继续埋头苦读。成绩确实提高了，但你的黑眼圈也加深了两个色号。时间又翻过一页，你对接下来的日子多了几分期待。"},{"text":"找人吐槽一顿，寻求陪伴","effects":{"social":6,"pressure":-6,"health":3},"narrative":"你给好朋友打了个电话，把心里的焦虑一股脑倒了出来。朋友听完说：'我也一样啊！我还以为就我这么焦虑呢。'你们互相吐槽了一个小时，最后都笑了。你发现，原来大家都一样，焦虑说出来就减半了。你在心里默默结算：时间没白花，人也踏实了些。"}]},{"id":"evt_scholarship","tags":["money","academic"],"weight":8,"minTurn":2,"maxTurn":6,"title":"奖学金评选","body":"既要绩点也要综测，材料准备很细碎。","choices":[{"text":"全力卷材料，冲一等","effects":{"gpa":0.1,"money":800,"pressure":10,"health":-4},"narrative":"你拿出了写论文的劲头来准备奖学金材料，每一份证明都精心排版，每一个奖项都详细描述。提交材料那天，你的文件夹厚得像一本小说。功夫不负有心人，你拿到了一等奖学金。看到银行卡余额的那一刻，你觉得所有的熬夜都值了。事情做完的那一刻，你吐出一口气，像把一块小石头从心里搬走了。"},{"text":"稳妥冲二等，别太伤身体","effects":{"money":400,"pressure":4,"health":2},"narrative":"你认真准备了材料，但没有为此拼命。'二等也不错，至少不用把自己逼得太紧。'你提交了申请，顺利拿到了二等奖学金。虽然不是最高，但你保持了良好的身心状态，这才是最重要的。你也没想太多，只是默默把这一格日子标成「还不错」。"},{"text":"放弃评选，专心长期能力","effects":{"skill":6,"pressure":-6},"narrative":"你决定不参与奖学金评选，把准备材料的时间用来学习实用技能。'奖学金是一次性的，能力是一辈子的。'你自学了一门编程语言，做了一个小项目。虽然少了奖学金，但你收获了更宝贵的东西。夜风从窗缝钻进来，你伸了个懒腰，觉得身体和精神都轻了一点。"}]},{"id":"evt_credit_rush","tags":["academic"],"weight":9,"minTurn":3,"maxTurn":7,"title":"选课抢课的网速","body":"教务系统秒崩，你在网吧/流量热点上疯狂刷新。","choices":[{"text":"死磕热门课给分好的老师","effects":{"gpa":0.12,"pressure":8,"skill":2},"narrative":"你提前半小时就守在电脑前，手指悬在鼠标上，像等待起跑的运动员。选课系统开放的一瞬间，你疯狂点击——然后系统崩了。你刷新了四十七次，终于在第五分钟抢到了心仪的课。你瘫在椅子上，感觉比打了一场游戏还累。你忽然明白，成长很多时候就是这样：不声不响，但方向清楚了一点。"},{"text":"保核心课，水课兜底轻松些","effects":{"gpa":-0.04,"health":6,"pressure":-6},"narrative":"你没有去抢那些热门课，而是选了几门轻松的水课搭配核心课。'课表太满会死的。'你深谙此道。结果你的课表看起来很轻松，你有大把时间做自己的事情。虽然绩点可能没那么高，但你的生活质量明显提升了。手机震了一下，是群里的梗图；你笑了一下，又关掉了屏幕。"},{"text":"托学长学姐指条明路","effects":{"social":5,"gpa":0.08,"money":-40},"narrative":"你请教学长学姐哪些课值得选、哪些老师给分好。学长发来一份详细的'选课避坑指南'，你如获至宝。按照指南选完课后，你请学长喝了杯奶茶表示感谢。信息差，有时候就是竞争力。这一页翻过去，下一件小事还在排队等你。"}]},{"id":"evt_exam_cheat_tempt","tags":["academic"],"weight":6,"title":"考场外的诱惑","body":"有人说有'捷径'，你喉咙发紧。","choices":[{"text":"拒绝，老老实实背书","effects":{"gpa":0.08,"pressure":-3,"health":2},"narrative":"你坚定地拒绝了所谓的'捷径'。'宁可挂科，不能挂人品。'你抱着课本老老实实地复习，虽然过程辛苦，但走进考场的时候你心里很踏实。考完试你长舒一口气——靠自己努力得来的成绩，才是最安心的。你把它写进待办里又划掉，像给今天盖了个「完成」的章。"},{"text":"侥幸心理——高风险","effects":{"gpa":-0.5,"pressure":20,"skill":-8},"narrative":"你抱着侥幸心理走了捷径……结果被发现了。后果很严重：成绩作废，通报批评，你的档案上留下了不光彩的一笔。你后悔莫及，但已经来不及了。这件事成了你大学里最大的教训——有些底线，永远不能碰。结果不算亮眼，但你坦然接受了这样的日常。"},{"text":"申请缓考/重修路线，别硬扛","effects":{"gpa":-0.15,"pressure":-8,"health":6},"narrative":"你意识到自己确实准备不足，与其铤而走险，不如申请缓考。虽然要多花一些时间，但至少是光明正大的。你利用多出来的时间认真复习，虽然成绩会受影响，但你的良心很安宁。你给自己倒了杯水，像给今天画了个小小的句号。"}]},{"id":"evt_sport_meet","tags":["health","social"],"weight":7,"minTurn":0,"maxTurn":4,"title":"运动会/体测","body":"体测成绩和综测挂钩，你纠结练不练。","choices":[{"text":"每晚跑步，顺路认识跑友","effects":{"health":10,"social":5,"pressure":-4,"skill":1},"narrative":"你开始了每晚的跑步计划。操场上你认识了一群同样在跑步的同学，你们建了一个'跑友群'，每天互相打卡。一个月后，你的体测成绩大幅提升，还交到了一群志同道合的朋友。跑步分泌的多巴胺，比任何奶茶都让人快乐。窗外天色暗下去，你心里却亮了一点点。"},{"text":"临时抱佛脚练一周","effects":{"health":4,"pressure":6},"narrative":"体测前一周你才开始突击训练，每天跑得气喘吁吁。虽然临时抱佛脚的效果有限，但至少比完全不练强。体测那天你勉强达标，你在心里发誓：下次一定提前准备。你摸了摸口袋里的校园卡，觉得它跟今天的你很合拍。"},{"text":"躺平，大不了补测","effects":{"health":-4,"pressure":-2,"gpa":-0.03},"narrative":"你选择了躺平，体测那天你跑得生无可恋。成绩不太理想，但你没有太在意。'大不了补测嘛。'你安慰自己。不过说实话，看着同学们轻松达标的样子，你还是有点后悔没有提前练练。舍友问你为什么傻笑，你说没事——其实只是心情不错。"}]},{"id":"evt_side_project","tags":["skill","y2"],"weight":9,"minTurn":3,"maxTurn":7,"title":"课外小项目","body":"几个朋友想搭一个小程序/自媒体试点子。","choices":[{"text":"主力开发，熬夜肝 MVP","effects":{"skill":14,"money":-150,"pressure":12,"health":-8},"narrative":"你成了项目的技术主力，连续两周熬夜写代码。咖啡杯在桌上排成了队列，你的GitHub贡献图绿得发亮。MVP上线那天，虽然用户只有你们自己，但看到产品跑起来的那一刻，你激动得差点哭了。这段经历后来成了你简历上最亮眼的一笔。夜深了，你摘下耳机，安静地结束了这一天。"},{"text":"每周固定半天维护，细水长流","effects":{"skill":8,"pressure":4,"social":6},"narrative":"你和朋友们约定每周六下午一起做项目，像参加一个固定的兴趣小组。进度虽然不快，但胜在稳定。几个月后，你们的小项目居然有了几百个用户。你发现，坚持比冲刺更重要。镜中的你有些疲惫，眼神却很稳——日子还在正轨上。"},{"text":"婉拒，怕耽误绩点","effects":{"gpa":0.12,"skill":2},"narrative":"你婉拒了朋友的邀请，决定把时间留给课业。'绩点是硬通货。'你对自己说。虽然错过了一个有趣的实践机会，但你的成绩确实保持得很好。只是偶尔看到朋友们讨论项目进展时，你会有一点点羡慕。你没写给谁的总结，却在心里默默点了点头。"}]},{"id":"evt_family_money","tags":["money","life"],"weight":8,"minTurn":1,"maxTurn":6,"title":"家里经济波动","body":"爸妈说话小心翼翼，你听懂了潜台词。","choices":[{"text":"接更多兼职分担","effects":{"money":350,"gpa":-0.12,"pressure":10,"health":-5},"narrative":"你默默增加了兼职的时间，周末几乎都在打工。虽然很累，但当你把一部分钱转给家里时，妈妈在电话里沉默了很久，然后说'你长大了'。那一刻，你觉得所有的辛苦都值得。楼道里有脚步声远去，你的大学生活又多了一层回声。"},{"text":"申请助学金/助学贷款资料","effects":{"money":500,"pressure":5,"social":3},"narrative":"你认真准备了助学金申请材料，辅导员很支持你，帮你走了绿色通道。申请批下来的时候，你松了一口气。你告诉自己：'这不是丢人的事，这是为了更好的未来。'你关上台灯，觉得今天像一张折好的纸，平平整整地收进抽屉里。"},{"text":"减少社交开支，自己做饭省一点","effects":{"money":180,"health":3,"social":-4},"narrative":"你开始精打细算：减少外出聚餐，自己在宿舍煮面、煮粥。虽然社交活动减少了，但你发现省下来的钱还挺可观的。而且自己做饭居然比食堂好吃——至少你是这么觉得的。风把窗帘轻轻吹动，你忽然觉得：日子就是这样一天天叠出来的。"}]},{"id":"evt_thesis_topic","tags":["academic","y4"],"weight":12,"minTurn":5,"maxTurn":7,"title":"毕设/论文选题","body":"导师给出几个方向，难度和出成果周期不一样。","choices":[{"text":"选挑战大的课题，赌一把亮点","effects":{"skill":10,"gpa":0.2,"pressure":15,"health":-6},"narrative":"你选了一个很有挑战性的课题，导师看了你的选题报告后说'这个有难度，你确定？'你点了点头。接下来的几个月，你经历了无数次实验失败、数据异常、方向调整。但当你最终完成论文时，导师说这是他今年看到的最好的本科论文之一。合上日记本，今天谈不上轰轰烈烈，却也算稳稳向前挪了一小步。"},{"text":"选稳妥课题，求顺利毕业","effects":{"gpa":0.12,"pressure":4,"health":4},"narrative":"你选了一个成熟的课题方向，前人的研究基础很扎实，你只需要在现有框架下做一些改进。过程很顺利，没有太多波折。虽然论文不够惊艳，但你按时完成了，而且整个过程心态很平稳。熄灯前你在脑子里复盘了一遍，觉得还行——明天继续。"},{"text":"找学长留的现成路径改改","effects":{"gpa":0.06,"pressure":-4,"skill":-2},"narrative":"你找到了学长留下的代码和数据，在他的基础上做了一些修改。虽然创新性不足，但胜在省时省力。答辩的时候老师问'你的创新点在哪里'，你支支吾吾地应付了过去。你在心里想：能毕业就行。你说不清具体收获了什么，心里却多了几分底气。"}]},{"id":"evt_interview_bootcamp","tags":["career"],"weight":8,"minTurn":5,"maxTurn":7,"title":"突击训练营","body":"某机构推销短期面试班，承诺内推——听听就好。","choices":[{"text":"交钱上车，极限刷题","effects":{"money":-1200,"skill":10,"pressure":8},"narrative":"你咬牙交了学费，开始了为期两周的面试魔鬼训练。每天从早到晚刷题、模拟面试、复盘。虽然贵，但效果确实明显——你的算法能力突飞猛进，面试技巧也提升了不少。结营的时候，你感觉自己脱胎换骨了。这些事不大，却让大学生活更具体、更鲜活。"},{"text":"白嫖公开课 + 自己刷题","effects":{"skill":7,"pressure":5},"narrative":"你没有报班，而是在网上找了一堆免费资源：公开课、面经、刷题网站。虽然没有人督促，但你靠着自律坚持了下来。效果虽然没有报班那么好，但省了一大笔钱。你在心里给自己点了个赞。你没有发朋友圈，但嘴角不自觉翘了一点。"},{"text":"不报，走内推和校友网络","effects":{"social":8,"skill":4},"narrative":"你没有报班，而是通过校友网络联系了几位在目标公司工作的学长学姐。他们给了你很多实用的建议，还帮你内推了简历。你发现，有时候人脉比刷题更重要。回到宿舍你突然觉得：嗯，今天也算没有白过。"}]},{"id":"evt_hackathon","tags":["skill","social"],"weight":7,"minTurn":2,"maxTurn":6,"title":"黑客松/比赛周末","body":"48 小时不破不立，奖品和精力不知哪个先来。","choices":[{"text":"组队冲奖，咖啡当水喝","effects":{"skill":12,"social":8,"health":-10,"pressure":12,"money":200},"narrative":"你和队友们在48小时内几乎没有合眼，咖啡和红牛是你们的燃料。最后几个小时，你们发现了一个致命bug，全员疯狂debug。提交前30秒，bug修好了。你们瘫在椅子上，相视而笑。最终你们拿了二等奖，奖金刚好够你们大吃一顿。时间又翻过一页，你对接下来的日子多了几分期待。"},{"text":"观赛学习，保存实力","effects":{"skill":4,"pressure":-4},"narrative":"你没有参赛，而是作为观众去观摩学习。看了别人的项目后，你大开眼界：原来还可以这样做！你记了很多笔记，虽然没有亲自上阵，但收获了不少灵感。你在心里默默结算：时间没白花，人也踏实了些。"},{"text":"不去，期末更重要","effects":{"gpa":0.14,"social":-3},"narrative":"你决定不去参加黑客松，把时间留给期末复习。看着朋友圈里别人晒比赛照片，你默默关掉手机继续背书。期末成绩出来后，你的选择被证明是正确的。事情做完的那一刻，你吐出一口气，像把一块小石头从心里搬走了。"}]},{"id":"evt_mental_counsel","tags":["life"],"weight":7,"conditions":{"all":[{"stat":"pressure","gte":55}]},"title":"心理咨询室的门","body":"你意识到自己可能有点撑不住了，门口徘徊很久。","choices":[{"text":"预约面谈，认真聊聊","effects":{"pressure":-18,"health":8,"social":2},"narrative":"你终于鼓起勇气走进了心理咨询室。咨询师很温柔，没有评判你，只是静静地听你说。你把积压了很久的情绪都说了出来，哭了一场。走出咨询室的时候，你感觉心里轻了很多。你发现，求助不是软弱，而是勇敢。你也没想太多，只是默默把这一格日子标成「还不错」。"},{"text":"先用运动与睡眠自救","effects":{"health":10,"pressure":-8},"narrative":"你决定先尝试自我调节：每天跑步半小时，晚上11点前睡觉。坚持了一周后，你的状态确实好了很多。虽然根本问题没有完全解决，但至少你有精力去面对了。夜风从窗缝钻进来，你伸了个懒腰，觉得身体和精神都轻了一点。"},{"text":"硬扛，当作软弱很丢人","effects":{"pressure":10,"health":-6},"narrative":"你告诉自己'这点压力算什么'，咬着牙继续硬扛。表面上你一切正常，但内心已经快要崩溃了。你开始失眠、食欲下降，身体发出了警告信号。也许，是时候重新考虑一下了……你忽然明白，成长很多时候就是这样：不声不响，但方向清楚了一点。"}]},{"id":"evt_leader_role","tags":["social"],"weight":8,"minTurn":2,"maxTurn":6,"title":"班委/社团骨干","body":"换届提名表发下来，意味着杂事和责任。","choices":[{"text":"竞选核心岗位，练组织力","effects":{"social":12,"skill":4,"pressure":8,"gpa":-0.06},"narrative":"你竞选了核心岗位，成功当选。从此你的微信消息就没停过：活动策划、人员协调、突发状况……你像一个微型CEO，在各种事务中周旋。虽然有时候很烦，但你的组织能力和沟通能力确实突飞猛进。手机震了一下，是群里的梗图；你笑了一下，又关掉了屏幕。"},{"text":"当个干事摸鱼摸奖","effects":{"social":5,"pressure":2},"narrative":"你选择了一个轻松的干事岗位，主要工作是'收到请回复'和偶尔搬搬东西。虽然贡献不大，但你混了个脸熟，综测加分也拿到了。你在心里给自己的摸鱼哲学点了个赞。这一页翻过去，下一件小事还在排队等你。"},{"text":"完全不参与","effects":{"skill":4,"gpa":0.08},"narrative":"你决定不参与任何学生工作，把时间全部留给自己。没有杂事打扰，你的学习效率很高。虽然少了些社交机会，但你享受这种简单纯粹的生活节奏。你把它写进待办里又划掉，像给今天盖了个「完成」的章。"}]},{"id":"evt_flu_season","tags":["health"],"weight":8,"title":"流感季","body":"寝室有人倒下了，咳嗽声此起彼落。","choices":[{"text":"口罩+消毒液拉满","effects":{"health":6,"money":-40},"narrative":"你立刻开启了防疫模式：口罩、消毒液、维生素C，全副武装。室友笑你太夸张，你说'预防大于治疗'。结果你是全寝室唯一一个没被传染的人。你在心里为自己的先见之明感到得意。结果不算亮眼，但你坦然接受了这样的日常。"},{"text":"继续熬夜赶工，赌免疫力","effects":{"health":-14,"gpa":0.08,"pressure":6},"narrative":"你觉得自己的免疫力很强，继续熬夜赶作业。结果你高估了自己——三天后你也倒下了，高烧39度，在床上躺了一周。虽然作业按时交了，但你付出了惨重的健康代价。下次流感季，你一定会戴口罩的。你给自己倒了杯水，像给今天画了个小小的句号。"},{"text":"主动休息两三天","effects":{"health":12,"gpa":-0.1,"pressure":-10},"narrative":"你果断请了假，在寝室好好休息了三天。喝水、睡觉、吃药，你像一个专业的病人。三天后你满血复活，虽然落下了一些课程，但你的身体感谢你的明智决定。窗外天色暗下去，你心里却亮了一点点。"}]},{"id":"evt_alumni_talk","tags":["career","social"],"weight":8,"minTurn":4,"maxTurn":7,"title":"校友分享会","body":"几位师兄师姐回校讲行业真话，问答环节很尖锐。","choices":[{"text":"会后加微信请教路径","effects":{"social":8,"skill":5},"narrative":"分享会结束后，你鼓起勇气走上前去加了师兄的微信。师兄很nice，不仅通过了你的好友申请，还给你发了一份他当年的求职笔记。你如获至宝，连夜研读。人脉这种东西，主动才会有故事。你摸了摸口袋里的校园卡，觉得它跟今天的你很合拍。"},{"text":"记下要点回去整理笔记","effects":{"skill":6,"gpa":0.06},"narrative":"你认真听了整场分享会，记了满满三页笔记。回去后你整理成了一份思维导图，发在了班级群里，同学们纷纷点赞。你发现，整理和分享知识的过程，本身就是一种学习。舍友问你为什么傻笑，你说没事——其实只是心情不错。"},{"text":"听完觉得焦虑，早点回寝","effects":{"pressure":8,"health":-3},"narrative":"听完师兄师姐的分享，你反而更焦虑了。'他们都那么优秀，我怎么办？'你闷闷不乐地回到寝室，刷了一晚上手机。其实你忽略了一个事实：那些师兄师姐也是从你现在的位置一步步走过来的。夜深了，你摘下耳机，安静地结束了这一天。"}]},{"id":"evt_lost_wallet","tags":["life"],"weight":5,"title":"丢钱包/手机","body":"你大脑一片空白，补办与挂失挤占了一整天。","choices":[{"text":"冷静按流程处理","effects":{"pressure":6,"money":-100,"skill":2},"narrative":"你深吸一口气，开始按流程处理：挂失银行卡、补办身份证、买新手机。虽然很麻烦，但你处理得有条不紊。你在心里感叹：成年人的标志就是遇到问题不再慌张，而是想办法解决。镜中的你有些疲惫，眼神却很稳——日子还在正轨上。"},{"text":"情绪崩溃大哭一场","effects":{"pressure":14,"health":-5},"narrative":"你崩溃了，在寝室大哭了一场。室友们围过来安慰你，给你递纸巾、倒热水。哭完之后你觉得好多了，虽然问题还在，但至少情绪释放了。有时候，哭一场也是解决问题的第一步。你没写给谁的总结，却在心里默默点了点头。"},{"text":"找辅导员和同学求助","effects":{"social":6,"pressure":-4},"narrative":"你第一时间找了辅导员和同学帮忙。辅导员帮你联系了保卫处，同学借了你一些钱应急。在大家的帮助下，你很快处理好了所有手续。你深深感受到了'出门靠朋友'这句话的分量。楼道里有脚步声远去，你的大学生活又多了一层回声。"}]},{"id":"evt_romance_commit","layer":"side","tags":["romance","relationship"],"weight":8,"minTurn":3,"maxTurn":11,"title":"关系边界讨论","body":"你们决定认真谈一次，重点不是糖，而是如何不互相消耗。","choices":[{"text":"约定每周固定高质量相处，其余时间各自成长","effects":{"social":8,"pressure":-6,"gpa":0.08},"setFlags":["romanceCommitted"],"narrative":"你们坐下来认真聊了一次，约定每周六是'我们时间'，其他时间各自专注学业。这个安排听起来不够浪漫，但执行起来效果出奇地好。你们既享受了恋爱的甜蜜，又没有耽误各自的成长。成年人的恋爱，边界感是最高级的浪漫。你关上台灯，觉得今天像一张折好的纸，平平整整地收进抽屉里。"},{"text":"全天候黏在一起，作业先放放","effects":{"social":10,"gpa":-0.2,"pressure":8,"health":-3},"setFlags":["romanceCommitted"],"narrative":"你们陷入了热恋，恨不得24小时黏在一起。食堂、图书馆、操场——校园里到处是你们的身影。甜蜜是真甜蜜，但代价也是真的：作业拖了一堆，期中成绩出来的时候你们都沉默了。恋爱很好，但挂科不好。风把窗帘轻轻吹动，你忽然觉得：日子就是这样一天天叠出来的。"},{"text":"先保持朋友，等忙完这学期","effects":{"pressure":-4,"health":3,"social":3},"narrative":"你们决定先保持现状，等这学期忙完再说。这个决定虽然有点遗憾，但很理智。你把精力都投入到了学习中，偶尔和对方一起吃个饭，保持着恰到好处的距离。有些事，不急于一时。合上日记本，今天谈不上轰轰烈烈，却也算稳稳向前挪了一小步。"}]},{"id":"evt_internship_offer","layer":"side","tags":["internship","career"],"semesterGte":5,"weight":9,"minTurn":5,"maxTurn":11,"title":"暑期实习 offer","body":"你收到一份实习邀请，薪资一般但含金量不错。","choices":[{"text":"接了，边干边学","effects":{"skill":12,"money":500,"pressure":8,"gpa":-0.1},"setFlags":["internshipReady"],"narrative":"你接下了这份实习，开始了朝九晚六的职场初体验。mentor很严格，但教了你很多东西。你第一次参加需求评审会，第一次写周报，第一次感受到'打工人'的酸甜苦辣。这段经历让你对职场有了真实的认知。熄灯前你在脑子里复盘了一遍，觉得还行——明天继续。"},{"text":"拒掉，专心绩点和考证","effects":{"gpa":0.18,"pressure":-3},"addFlags":{"certProgress":1},"narrative":"你婉拒了实习offer，决定利用暑假专心提升绩点和考证。你在图书馆里度过了一个充实的夏天，考下了一门证书，绩点也稳中有升。虽然少了实习经历，但你相信扎实的基础同样重要。你说不清具体收获了什么，心里却多了几分底气。"},{"text":"先做远程兼职试试水","effects":{"money":260,"skill":5,"pressure":3},"setFlags":["internshipReady"],"narrative":"你和公司商量了一个远程兼职的方案，不用每天去办公室，但也能参与项目。你在宿舍里远程办公，既体验了工作的感觉，又保持了时间的灵活性。这种折中方案意外地适合你。这些事不大，却让大学生活更具体、更鲜活。"}]},{"id":"evt_civil_exam_bootcamp","layer":"side","tags":["civil_service","public_institution"],"weight":8,"minTurn":6,"maxTurn":11,"title":"行测申论特训班","body":"室友突然开始 6 点背申论，你怀疑自己是不是落后了。","choices":[{"text":"加入备考，建立错题本","effects":{"gpa":0.12,"pressure":7,"health":-2},"setFlags":["civilTrack"],"addFlags":{"civilProgress":1},"narrative":"你也加入了考公大军，每天早起刷行测，晚上写申论。你建立了一个错题本，把每次做错的题都记录下来反复研究。虽然过程枯燥，但当你看到正确率一点点提升时，那种成就感是真实的。你没有发朋友圈，但嘴角不自觉翘了一点。"},{"text":"走考编方向，盯教师/事业单位","effects":{"gpa":0.1,"pressure":5,"social":3},"setFlags":["publicInstitutionTrack"],"addFlags":{"civilProgress":1},"narrative":"你选择了考编方向，开始关注教师和事业单位的招聘信息。相比考公，考编的竞争稍微小一些，而且工作节奏更适合你。你开始有针对性地准备，心里有了明确的方向。回到宿舍你突然觉得：嗯，今天也算没有白过。"},{"text":"不跟风，继续市场化路线","effects":{"skill":5,"pressure":-4},"narrative":"你没有被考公热潮裹挟，继续走市场化路线。'体制内很好，但不适合我。'你清楚自己的选择。你把时间花在了提升专业技能上，为进入企业做好了准备。时间又翻过一页，你对接下来的日子多了几分期待。"}]},{"id":"evt_certificate_rush","layer":"side","tags":["cert"],"weight":8,"minTurn":2,"maxTurn":11,"title":"考证月历","body":"英语、教资、计算机、会计，报名入口像打地鼠。","choices":[{"text":"连报两门，能卷则卷","effects":{"gpa":0.1,"pressure":9,"health":-4},"addFlags":{"certProgress":2},"narrative":"你一口气报了两门考试，开始了双线作战。上午背英语单词，下午刷计算机题库，晚上还要复习专业课。你的日程表满得像春运火车票。虽然累到怀疑人生，但当你两门都通过的时候，你觉得一切都值了。你在心里默默结算：时间没白花，人也踏实了些。"},{"text":"只报一门，稳扎稳打","effects":{"gpa":0.06,"pressure":2},"addFlags":{"certProgress":1},"narrative":"你只报了一门最需要的证书考试，集中精力准备。没有分散精力，你的复习效率很高。考试那天你信心满满地走进考场，出来的时候就知道自己稳了。事情做完的那一刻，你吐出一口气，像把一块小石头从心里搬走了。"},{"text":"先不考，技能优先","effects":{"skill":6,"pressure":-3},"narrative":"你决定暂时不考证，把时间用来学习实用技能。'证书是敲门砖，但能力才是铁饭碗。'你花时间做了一个完整的项目，虽然简历上少了一行证书，但多了一个亮眼的作品。你也没想太多，只是默默把这一格日子标成「还不错」。"}]},{"id":"evt_student_union","layer":"side","tags":["student_work","club"],"weight":8,"minTurn":1,"maxTurn":10,"title":"学生工作连轴转","body":"活动审批、报销、会场布置，群公告比论文还长。","choices":[{"text":"接负责人，锻炼组织能力","effects":{"social":12,"pressure":9,"gpa":-0.08},"addFlags":{"studentWork":1},"narrative":"你接下了活动负责人的重任，从此过上了'手机不敢静音'的生活。活动当天出了各种幺蛾子：音响坏了、嘉宾迟到、物资不够……你像一个消防员到处救火。活动结束后你瘫在椅子上，虽然累但很有成就感。夜风从窗缝钻进来，你伸了个懒腰，觉得身体和精神都轻了一点。"},{"text":"当执行，不背锅但有贡献","effects":{"social":6,"pressure":3},"addFlags":{"studentWork":1},"narrative":"你选择做一个靠谱的执行者，按时完成分配的任务，但不过度揽责。活动顺利结束后，你默默退场，深藏功与名。这种'有参与但不透支'的方式很适合你。你忽然明白，成长很多时候就是这样：不声不响，但方向清楚了一点。"},{"text":"撤退，保命要紧","effects":{"health":4,"pressure":-6},"narrative":"你果断退出了学生工作，把时间还给了自己。没有了开不完的会和回不完的消息，你的生活突然清净了很多。你在心里感叹：有时候，撤退也是一种智慧。手机震了一下，是群里的梗图；你笑了一下，又关掉了屏幕。"}]},{"id":"evt_dorm_or_offcampus","layer":"side","tags":["dorm","off_campus"],"weight":7,"minTurn":3,"maxTurn":11,"title":"宿舍还是外宿","body":"你在效率和社交之间反复横跳，准备做出生活方式选择。","choices":[{"text":"继续住寝室，和舍友磨合","effects":{"social":7,"pressure":-2,"health":2},"addFlags":{"dormProgress":1},"narrative":"你决定继续住寝室，和舍友们慢慢磨合。你们一起制定了寝室公约，互相尊重彼此的习惯。渐渐地，寝室变成了一个温暖的小窝，你们会在深夜聊人生、聊理想，这些时光成了大学里最珍贵的回忆。这一页翻过去，下一件小事还在排队等你。"},{"text":"外宿通勤，换一个安静空间","effects":{"health":8,"money":-420,"social":-4,"gpa":0.08},"setFlags":["offCampus"],"narrative":"你在校外租了一个小单间，终于有了完全属于自己的空间。虽然房租不便宜，通勤也花时间，但安静的环境让你的学习效率大幅提升。你在房间里贴满了便利贴和计划表，像一个微型指挥中心。你把它写进待办里又划掉，像给今天盖了个「完成」的章。"},{"text":"学期内不折腾，先凑合","effects":{"pressure":3,"money":80},"narrative":"你决定这学期先不折腾，维持现状。虽然寝室条件不是最理想的，但至少省心省钱。你把省下来的精力都用在了学习上，打算下学期再做决定。结果不算亮眼，但你坦然接受了这样的日常。"}]},{"id":"evt_research_rotation","layer":"side","tags":["research","lab"],"weight":8,"minTurn":5,"maxTurn":11,"title":"课题组轮转","body":"导师让你挑一个方向试做 mini project，看你是否真适合科研。","choices":[{"text":"咬牙做完并复盘","effects":{"skill":11,"gpa":0.14,"pressure":10,"health":-4},"setFlags":["researchTrack"],"addFlags":{"researchProgress":1},"narrative":"你咬牙完成了这个mini project，从文献调研到实验设计到数据分析，完整地走了一遍科研流程。虽然过程中无数次想放弃，但做完之后你发现自己对科研有了真正的理解。导师看了你的报告后说'不错，有潜力'。你给自己倒了杯水，像给今天画了个小小的句号。"},{"text":"浅尝辄止，记录经验即可","effects":{"skill":5,"pressure":2},"addFlags":{"researchProgress":1},"narrative":"你尝试了一下，但没有深入。你记录了实验的基本流程和自己的感受，对科研有了初步的了解。虽然不够深入，但至少你知道科研大概是什么样子了。窗外天色暗下去，你心里却亮了一点点。"},{"text":"不做，转去实习赛道","effects":{"skill":4,"money":120},"setFlags":["internshipReady"],"narrative":"你决定不做这个mini project，把时间转向实习。'科研不适合我，我想早点接触业界。'你清楚地认识到了自己的偏好，把精力投入到了找实习上。你摸了摸口袋里的校园卡，觉得它跟今天的你很合拍。"}]},{"id":"evt_contest_cycle","layer":"side","tags":["contest"],"weight":7,"minTurn":4,"maxTurn":11,"title":"竞赛季连战","body":"比赛一个接一个，你的队伍开始讨论要不要 all in。","choices":[{"text":"连打两场，冲奖冲简历","effects":{"skill":13,"pressure":11,"health":-6,"money":180},"addFlags":{"contestProgress":2},"narrative":"你们连打了两场比赛，像打了鸡血一样。第一场拿了三等奖，第二场冲到了二等奖。虽然累到虚脱，但奖状和奖金让一切都值得。你的简历上多了两行亮眼的竞赛经历。舍友问你为什么傻笑，你说没事——其实只是心情不错。"},{"text":"打一场试水，保留体力","effects":{"skill":7,"pressure":4},"addFlags":{"contestProgress":1},"narrative":"你们选择只参加一场比赛，集中精力准备。虽然没有拿奖，但你们积累了宝贵的经验，而且没有因此透支身体。你在心里想：下次准备充分了再来。夜深了，你摘下耳机，安静地结束了这一天。"},{"text":"不打，转向课程项目","effects":{"gpa":0.12,"pressure":-3},"narrative":"你决定不参加竞赛，把精力投入到课程项目中。虽然没有竞赛奖项，但你的课程项目做得很出色，绩点也稳中有升。镜中的你有些疲惫，眼神却很稳。你没写下总结，却在心里默默点了点头。"}]},{"id":"evt_practice_trip","layer":"side","tags":["social_practice","volunteer"],"weight":7,"minTurn":2,"maxTurn":9,"title":"暑期社会实践","body":"学院组织调研和支教，成果要做成报告和答辩。","choices":[{"text":"参加并负责汇报","effects":{"social":10,"skill":4,"pressure":5},"addFlags":{"studentWork":1},"narrative":"你不仅参加了社会实践，还主动承担了汇报的任务。答辩那天你穿着正装站在台上，虽然紧张但表现得很出色。评委老师频频点头，你的团队拿了优秀实践团队。楼道里有脚步声远去，你的大学生活又多了一层回声。"},{"text":"参加但只做执行","effects":{"social":6,"pressure":2},"narrative":"你参加了社会实践，但只做执行层面的工作。虽然贡献不算突出，但你体验了实践的整个过程，也认识了一些新朋友。你关上台灯，觉得今天像一张折好的纸，平平整整地收进抽屉里。风把窗帘轻轻吹动，你忽然觉得：日子就是这样一天天叠出来的。"},{"text":"不去，利用假期打工","effects":{"money":360,"health":-2},"narrative":"你决定不去社会实践，利用假期打工赚钱。虽然少了实践经历，但你赚到了一笔可观的生活费。你在心里盘算：实践可以以后再补，但钱现在就需要。合上日记本，今天谈不上轰轰烈烈，却也算稳稳向前挪了一小步。"}]},{"id":"evt_cert_or_love_joke","layer":"side","tags":["romance","cert"],"weight":6,"minTurn":4,"maxTurn":11,"title":"考证还是约会","body":"你在打印店门口一边背单词一边回消息，觉得自己像并发程序。","choices":[{"text":"上午刷题下午约会，时间管理拉满","effects":{"gpa":0.06,"social":6,"pressure":6},"addFlags":{"certProgress":1},"setFlags":["romanceCommitted"],"narrative":"你开启了极限时间管理模式：上午在图书馆刷题，下午去约会，晚上回来继续学习。虽然累，但你两边都没耽误。你在心里给自己竖了个大拇指：什么叫时间管理大师？这就是。熄灯前你在脑子里复盘了一遍，觉得还行——明天继续。"},{"text":"闭关备考，先把证拿下","effects":{"gpa":0.12,"social":-4,"pressure":4},"addFlags":{"certProgress":1},"narrative":"你狠心拒绝了所有约会邀请，闭关备考。对方发来消息，你回复'在复习，考完联系'。虽然有点残忍，但你清楚自己的优先级。证书拿到手之后，你才松了口气。你说不清具体收获了什么，心里却多了几分底气。"},{"text":"管他呢，先去吃火锅","effects":{"health":6,"money":-120,"pressure":-7},"narrative":"你把书本一扔：'考证可以再考，火锅不能不吃！'你们去吃了一顿酣畅淋漓的火锅，聊了很多有的没的。虽然复习进度落后了，但你的心情好了很多。有时候，一顿火锅比一套真题更能治愈人。这些事不大，却让大学生活更具体、更鲜活。"}]},{"id":"evt_startup_pitch","layer":"side","tags":["career","contest"],"weight":6,"minTurn":6,"maxTurn":11,"title":"创业路演","body":"你的小点子终于要上台，被问到盈利模型时全队沉默三秒。","choices":[{"text":"硬着头皮继续做，边学边改","effects":{"skill":9,"social":6,"pressure":9,"money":-200},"setFlags":["startupIntent"],"narrative":"虽然路演被怼得体无完肤，但你们没有放弃。你们根据评委的反馈大改了产品方向，从零开始重新做。虽然烧了不少钱，但你们学到了在课堂上学不到的东西。创业就是这样——不断被打脸，然后爬起来继续。你没有发朋友圈，但嘴角不自觉翘了一点。"},{"text":"暂停项目，回归求职主线","effects":{"skill":4,"pressure":-3,"money":100},"setFlags":["internshipReady"],"narrative":"路演之后你们冷静地评估了一下，决定暂停项目，回归求职主线。'创业需要时机和资源，我们现在还不具备。'这个决定虽然有点遗憾，但很理智。回到宿舍你突然觉得：嗯，今天也算没有白过。"},{"text":"转成比赛作品混个奖","effects":{"skill":6,"money":200,"pressure":4},"addFlags":{"contestProgress":1},"narrative":"你们把项目包装成了一个比赛作品，参加了一个创新创业大赛。虽然没有真正去创业，但项目在比赛中拿了个奖，也算没有白费之前的努力。时间又翻过一页，你对接下来的日子多了几分期待。"}]},{"id":"evt_exam_week_meme","layer":"side","tags":["life","academic"],"weight":8,"minTurn":1,"maxTurn":11,"title":"期末表情包大赏","body":"群里全是「这周开始复习来得及吗」的表情包，你笑着笑着就打开了课件。","choices":[{"text":"边笑边学，情绪稳定输出","effects":{"gpa":0.1,"pressure":-2},"narrative":"你在复习群里和大家一起斗图、吐槽考试，但该学的时候一点不含糊。你把最常戳心的一张复习警告图设成了手机壁纸，每次想玩手机看到那张脸就默默放下了。这种'笑着卷'的方式意外地高效。你在心里默默结算：时间没白花，人也踏实了些。"},{"text":"刷图到凌晨，第二天自闭","effects":{"health":-8,"pressure":7,"gpa":-0.08},"narrative":"你沉迷于群里的斗图大战，不知不觉刷到了凌晨三点。第二天你顶着两个黑眼圈去考试，脑子一片空白。考完试你在群里发了一个'我没了'的表情包，这次是真的没了。事情做完的那一刻，你吐出一口气，像把一块小石头从心里搬走了。"},{"text":"拉同学开互助复习房","effects":{"social":6,"gpa":0.08,"pressure":2},"narrative":"你在群里发起了一个'互助复习房'，几个同学响应了。你们约在图书馆的讨论区，互相讲解重点、分享笔记。虽然偶尔还是会跑偏聊八卦，但总体效率比一个人复习高多了。你也没想太多，只是默默把这一格日子标成「还不错」。"}]},{"id":"evt_postgrad_interview","layer":"main","tags":["research","academic"],"weight":11,"semesterGte":7,"semesterLte":7,"title":"推免面试周","body":"{playerName}你站在教学楼走廊里，手里那份个人陈述已经被你翻卷边了。","choices":[{"text":"冲刺准备，认真打磨每一段经历","effects":{"gpa":0.12,"skill":8,"pressure":10,"health":-4},"setFlags":["postgradLockedIn","researchTrack"],"narrative":"你把每一段经历都打磨得像宝石一样闪闪发光。面试的时候，老师问你'为什么选择这个方向'，你从大一的启蒙课讲到了现在的科研经历，逻辑清晰，情感真挚。面试结束后，你走出教学楼，阳光正好。夜风从窗缝钻进来，你伸了个懒腰，觉得身体和精神都轻了一点。"},{"text":"保持平衡，边投递边准备","effects":{"gpa":0.08,"skill":5,"pressure":4},"setFlags":["researchTrack"],"narrative":"你没有把所有鸡蛋放在一个篮子里，一边准备推免面试，一边也在关注其他机会。面试表现中规中矩，但你的心态很稳。你知道，无论结果如何，你都有备选方案。你忽然明白，成长很多时候就是这样：不声不响，但方向清楚了一点。"},{"text":"放弃推免，转向就业/考公路线","effects":{"pressure":-3,"money":120,"skill":3},"narrative":"你认真思考后决定放弃推免，转向就业或考公。'读研不是唯一的路。'你对自己说。做出这个决定后，你反而轻松了很多，开始全力准备求职。手机震了一下，是群里的梗图；你笑了一下，又关掉了屏幕。"}]},{"id":"evt_thesis_defense_final","layer":"main","tags":["academic"],"weight":12,"semesterGte":8,"semesterLte":8,"title":"毕设与答辩","body":"终于来到大四下终局，PPT、论文、答辩服全挤在同一周。","choices":[{"text":"全力冲刺，打磨到最后一页","effects":{"gpa":0.16,"skill":6,"pressure":8,"health":-3},"narrative":"你把PPT打磨到了最后一刻，每一页的动画都精心设计，每一个数据都反复核对。答辩那天你穿着正装站在讲台上，虽然紧张但准备充分。答辩结束后，评委老师说'不错，看得出来下了功夫'。你长舒一口气——大学最后一关，过了。这一页翻过去，下一件小事还在排队等你。"},{"text":"稳妥毕业，保证不过线就行","effects":{"gpa":0.08,"pressure":2,"health":2},"narrative":"你没有追求完美，只求顺利通过。答辩表现中规中矩，没有出彩也没有翻车。答辩结束后你走出教室，心里想：能毕业就行，人生还长着呢。你把它写进待办里又划掉，像给今天盖了个「完成」的章。"},{"text":"交给命运，先活过这周","effects":{"gpa":-0.12,"pressure":-2,"health":3},"narrative":"你这周的状态不太好，答辩准备得不够充分。答辩的时候被老师问住了几个问题，你支支吾吾地作答。虽然通过了，但成绩不太理想。你在心里想：能过就行，大学四年已经够累了。结果不算亮眼，但你坦然接受了这样的日常。"}]},{"id":"evt_pick_mentor","layer":"side","tags":["academic"],"weight":99,"minTurn":0,"maxTurn":23,"title":"双向奔赴的课题组（伪）","body":"学院开放导师意向征集，你在三位候选之间徘徊——传说中选对导师等于选对四年副本路线；DDL是第一生产力这句话，在课题组里会变成「导师是第一生产力」。","choices":[{"text":"跟随 {mentor1}（科研主线）","mentorIndex":0,"effects":{"skill":4,"pressure":3},"narrative":"你把报名表递给第一位导师，仿佛按下了一条更长更难也更酷的关卡线；此后组会、周报与文献会像早八刺客一样准时出现，但你心里有底——这条路能把简历镀上一层真正的硬度。你给自己倒了杯水，像给今天画了个小小的句号。"},{"text":"跟随 {mentor2}（工程落地）","mentorIndex":1,"effects":{"skill":5,"social":2,"pressure":4},"narrative":"你选了更偏项目与交付的那位，从此接口、联调、演示稿会像奶茶订单一样排队到来；小镇做题家模式被迫升级为「需求变更耐受模式」，但你拿到了能写进作品集的真东西。截图丢进相册，简历多一行真话；再来一次你会少点心慌，多点利落。"},{"text":"跟随 {mentor3}（自由探索）","mentorIndex":2,"effects":{"gpa":0.06,"pressure":-2},"narrative":"你选了风格更松的一位，从此进度条更像自助通关：少了push也可能少了确定感；你在自律与摸鱼之间反复横跳，却发现自由的代价是自己对自己下手——也算成年礼。截图丢进相册，简历多一行真话；再来一次你会少点心慌，多点利落。"}]},{"id":"evt_romance_intro","layer":"side","tags":["romance","social"],"weight":99,"minTurn":0,"maxTurn":23,"title":"心动副本加载中","body":"大三的节奏像按了快进，突然有人问你要不要一起走夜路、一起自习、一起把尴尬聊成笑料；你意识到恋爱不是支线任务，而是会改写时间分配的系统性更新。","choices":[{"text":"靠近 {romance1}","romancePickIndex":0,"effects":{"social":6,"pressure":-4,"gpa":-0.04},"narrative":"你选了更近的那条路，聊天框开始变成心跳记录仪；从此日程表里多了「顺便见面」，也开始学会把话说完整——暧昧三连击不一定每次都赢，但至少你在练习真诚。截图丢进相册，简历多一行真话；再来一次你会少点心慌，多点利落。"},{"text":"靠近 {romance2}","romancePickIndex":1,"effects":{"social":6,"pressure":-3},"narrative":"你把偏好写在行动上而不是嘴上，关系像慢热型编译——第一次很慢，缓存命中后就顺滑起来；你们偶尔也为 ddl 吵架，但吵完还是会一起去食堂治疗灵魂。截图丢进相册，简历多一行真话；再来一次你会少点心慌，多点利落。"},{"text":"先专注学业，暂不开始恋情","romanceSkip":true,"effects":{"gpa":0.08,"skill":4,"pressure":2},"narrative":"你点了跳过恋情章节，决定先把主线推到「更像样的自己」；朋友圈看起来更冷酷，其实你只是把温柔留给未来的时间表——谁说单身就不能过得像热血番。截图丢进相册，简历多一行真话；再来一次你会少点心慌，多点利落。"}]},{"id":"evt_npc_roommate_lane","npcRef":"npc_lin","tags":["life"],"weight":8,"minTurn":1,"maxTurn":20,"title":"寝室时区战争","body":"{roommate1}把闹钟设成清晨六点，全寝室被动加入「卷王时区」；你一边吐槽一边发现自己的睡眠账户正在透支，像被早八刺客反复偷袭。","choices":[{"text":"正面沟通值日表与熄灯时间","effects":{"social":4,"pressure":-5,"health":2},"npcAffinityDelta":{"npc_lin":4},"narrative":"你把话说开，像打开了寝室路由器管理页面：限速、分流、黑白名单一次到位；从此矛盾还在，但至少变成可讨论的网络协议，而不是随机断网。截图丢进相册，简历多一行真话；再来一次你会少点心慌，多点利落。"},{"text":"买耳塞眼罩进入自适应模式","effects":{"pressure":6,"health":-2,"gpa":0.05},"narrative":"你选择装备流打法，把矛盾改成与自己的和解；代价是心里仍有小火苗，但至少不会影响你在课上当场睡着——也算战术胜利。截图丢进相册，简历多一行真话；再来一次你会少点心慌，多点利落。"}]},{"id":"evt_npc_mentor_push","npcRef":"npc_mentor_zhang","tags":["research","academic"],"weight":9,"minTurn":4,"maxTurn":22,"conditions":{"all":[{"flag":"primaryMentor"}]},"title":"组会现场直播","body":"{primaryMentor}在组会上把你的进度条拉到全场可见：夸奖像稀有掉落，沉默像常态地图；你突然理解什么叫「导师是第一生产力」——压力也是。","choices":[{"text":"连夜补齐材料硬顶一波","effects":{"skill":6,"pressure":8,"health":-4},"npcAffinityDelta":{"npc_mentor_zhang":5},"narrative":"你用通宵把图表补齐，像在游戏里赶赛季结算；第二天导师点头的一瞬间，你觉得发际线虽然受伤，但经验值真的到账。截图丢进相册，简历多一行真话；再来一次你会少点心慌，多点利落。"},{"text":"坦诚困难请求拆任务","effects":{"pressure":-3,"social":3},"npcAffinityDelta":{"npc_mentor_zhang":2},"narrative":"你学会了把不会写进周报里，导师反而给了更可执行的切片；原来成年人的进度条也能分期付款。截图丢进相册，简历多一行真话；再来一次你会少点心慌，多点利落。"}]},{"id":"evt_npc_romance_cafe","npcRef":"npc_rom_h1","tags":["romance","social"],"weight":8,"minTurn":6,"maxTurn":23,"title":"咖啡馆座位抽签","body":"你和心动对象同时看上最后一个靠窗位——空气突然安静得像期末考场；小镇做题家本能让你想退，但心里有个声音说「这次别逃」。","choices":[{"text":"大方拼桌一起坐","effects":{"social":8,"pressure":-5},"npcAffinityDelta":{"npc_rom_h1":6},"narrative":"你们拼桌成功，话题从课程聊到人生再到八卦，咖啡杯像小型社交路由器；后来你发现主动一步并不丢人，丢人的是一直在脑内预习却没交卷。截图丢进相册，简历多一行真话；再来一次你会少点心慌，多点利落。"},{"text":"让给对方，装冷静离开","effects":{"social":-2,"pressure":4},"narrative":"你礼貌撤退，心里上演十万字虐恋；当晚朋友圈发「随缘」——典型嘴硬心软的前奏。截图丢进相册，简历多一行真话；再来一次你会少点心慌，多点利落。"}]},{"id":"evt_med_night_shift_practice","layer":"side","schoolScopes":["med"],"majorScopes":["medicine"],"tags":["academic","research","medicine"],"weight":9,"minTurn":2,"maxTurn":23,"title":"夜班见习排班","body":"附属医院临时开放夜班见习名额，值班群里已经开始抢位。","choices":[{"text":"主动顶班，跟急诊老师实操","effects":{"skill":14,"gpa":0.12,"pressure":14,"health":-8},"narrative":"你接下夜班，跟着老师一路从分诊跑到处置室。脚步几乎没停，脑子却越来越清醒。天亮时你累到说不出话，但第一次真正感受到这门专业的重量。"},{"text":"只接半夜段，保证第二天能上课","effects":{"skill":8,"gpa":0.08,"pressure":5,"health":-2},"narrative":"你和带教老师沟通后只接了半夜时段。强度可控，关键流程也都看到了。虽然没那么燃，但你把学习和体力都维持在了可持续区间。"},{"text":"为了补贴多接两轮，硬扛到底","effects":{"money":220,"skill":7,"pressure":16,"health":-12,"gpa":-0.05},"narrative":"你连着接了两轮排班，补贴到账很快，疲惫也来得更快。回宿舍时你甚至忘了自己把钥匙放哪。短期收益有了，代价是身体在明确抗议。"},{"text":"把名额让给别人，回去睡觉回血","effects":{"health":8,"pressure":-8,"skill":-2},"narrative":"你看着群消息一路刷屏，最后把手机一扣直接睡了。第二天精神状态好了不少，虽然错过了实操机会，但至少没有把自己透支到崩。"}]},{"id":"evt_agri_field_trial","layer":"side","schoolScopes":["agricultural"],"tags":["research","life","agriculture"],"weight":8,"minTurn":1,"maxTurn":22,"title":"试验田突发虫害","body":"老师在群里发来照片：样地出现虫害，今晚就得决定处理方案。","choices":[{"text":"连夜做监测方案，按流程处理","effects":{"skill":11,"gpa":0.08,"pressure":8,"health":-3},"narrative":"你背着设备进地，逐块记录虫口密度，再按流程安排防治。过程琐碎但扎实，报告数据漂亮，老师直接把你列进后续项目名单。"},{"text":"跟队做执行，学习实地流程","effects":{"skill":6,"health":2,"pressure":3},"narrative":"你跟着师兄师姐跑流程，主要负责记录和样本整理。虽然不是主导，但你把田间操作的关键步骤全摸清了，心里更有底。"},{"text":"省步骤抢进度，结果返工","effects":{"skill":3,"gpa":-0.08,"pressure":10,"money":-90},"narrative":"你为了赶时间省了几个检测步骤，结果数据不可靠，整组返工。时间和经费都被吃掉，大家的脸色也不太好看。"},{"text":"装作没看到消息，先回寝室躺平","effects":{"pressure":-6,"health":4,"social":-4,"gpa":-0.05},"narrative":"你把群消息静音，决定今晚谁也别找你。人是休息好了，但第二天被问进度时你只能尴尬点头，队友信任值也掉了一截。"}]},{"id":"evt_finance_sim_trading","layer":"side","schoolScopes":["finance"],"majorScopes":["finance_major","biz"],"tags":["career","money","finance"],"weight":8,"minTurn":2,"maxTurn":23,"title":"模拟交易赛","body":"学院办了两周模拟交易赛，收益榜和实习推荐直接挂钩。","choices":[{"text":"做模型 + 纪律交易，稳扎稳打","effects":{"skill":10,"money":220,"pressure":7,"gpa":0.06},"narrative":"你先搭好策略框架再下单，节奏不快但回撤可控。最终排名进前列，老师也愿意给你写一段像样的推荐评语。"},{"text":"跟着小组共识走，收益中规中矩","effects":{"skill":6,"social":5,"money":120,"pressure":3},"narrative":"你把决策放到组内讨论，执行更稳，情绪波动也小。收益不是最高，但团队协作和复盘都做得完整。"},{"text":"重仓梭哈，赌一把翻盘","effects":{"money":-260,"pressure":12,"health":-4,"skill":4},"narrative":"你顶不住排行榜压力，直接重仓博高波动。开盘一度很爽，收盘一看净值直接跳水，整个人像被行情狠狠按在地上。"},{"text":"不看盘了，拿奖金当空气","effects":{"pressure":-7,"health":5,"skill":-3},"narrative":"你关掉交易软件，转头去操场散步。收益榜跟你再无关系，焦虑也确实降了不少。只是复盘会时你几乎没法贡献内容。"}]},{"id":"evt_ai_compute_queue","layer":"side","majorScopes":["ai","data_science","cs"],"tags":["skill","research","ai"],"weight":9,"minTurn":3,"maxTurn":23,"title":"实验室算力排队","body":"公共 GPU 队列排到两天后，你要决定这周项目怎么推进。","choices":[{"text":"优化特征与小样本实验先跑起来","effects":{"skill":12,"gpa":0.08,"pressure":6,"health":-2},"narrative":"你先做数据清洗和轻量实验，把可验证假设全部前置。等到算力窗口一开，模型几乎一次就跑通，效率拉满。"},{"text":"借同学机器分摊任务，慢慢推","effects":{"skill":7,"social":5,"pressure":3},"narrative":"你找了几个同学拼资源，把任务拆分并行跑。速度一般，但过程稳定，大家还顺便共享了不少脚本和调参经验。"},{"text":"盲目堆参数，反复炸显存","effects":{"skill":4,"pressure":11,"health":-5,"gpa":-0.04},"narrative":"你一股脑把参数拉满，训练脚本报错得比你刷新日志还快。时间花了很多，结论却没沉淀下来，情绪也被拖进低谷。"},{"text":"算了不训了，先刷视频摸鱼","effects":{"pressure":-5,"health":3,"skill":-4,"gpa":-0.06},"narrative":"你打开视频平台说只看十分钟，回神已经两小时后。短期确实轻松，项目进度条也肉眼可见地停住了。"}]},{"id":"evt_law_moot_court","layer":"side","schoolScopes":["police_academy"],"majorScopes":["law","civil_exam"],"tags":["academic","social","law"],"weight":8,"minTurn":2,"maxTurn":23,"title":"模拟法庭赛前夜","body":"你们组抽到了最难的争点，法条检索和证据链都还没完全闭环。","choices":[{"text":"重写论证结构，逐条补证据","effects":{"skill":10,"gpa":0.1,"pressure":8,"health":-3},"narrative":"你从争点拆解开始重搭整套论证，把每个结论都对上法条与证据。上场时你思路非常清楚，老师点评也明显偏正面。"},{"text":"保守发挥，主打不失误","effects":{"skill":6,"pressure":2,"social":4},"narrative":"你们选择稳妥打法，不抢高风险辩点，重点保证表达与时间控制。结果不算惊艳，但流程顺畅，团队配合也很顺。"},{"text":"照搬旧稿，临场靠嘴硬扛","effects":{"gpa":-0.08,"pressure":10,"social":-3,"skill":3},"narrative":"你抱着侥幸心理沿用旧稿，结果现场被追问关键证据时节节后退。台下同学都替你捏汗，赛后复盘气氛也有点沉。"},{"text":"临时请假不参赛，直接摆烂","effects":{"pressure":-6,"health":4,"social":-6,"gpa":-0.06},"narrative":"你临时退赛，短期是轻松了，但队友直接少一个发言位。比赛结束后群里没人责怪你，沉默本身已经很说明问题。"}]},{"id":"evt_foreign_lang_sim_conf","layer":"side","schoolScopes":["foreign_language","sino_foreign"],"majorScopes":["news","liberal"],"tags":["social","career","language"],"weight":7,"minTurn":1,"maxTurn":23,"title":"模拟国际会议","body":"你被分到高压议题组，要在全英文讨论里兼顾观点和节奏。","choices":[{"text":"提前写发言提纲并做术语库","effects":{"social":9,"skill":8,"pressure":6,"gpa":0.05},"narrative":"你把术语和发言节奏都准备到位，现场输出非常稳定。会后还有老师主动来聊你的表达框架，收获感拉满。"},{"text":"主打倾听与补充，稳住存在感","effects":{"social":6,"skill":4,"pressure":2},"narrative":"你把重心放在听懂和关键时刻补位，不抢麦但也不掉线。虽然不算最亮眼，但团队协作里你的价值很清晰。"},{"text":"全程硬撑，听不懂也不求助","effects":{"pressure":9,"social":-3,"skill":2,"health":-2},"narrative":"你怕丢脸不愿确认信息，结果几次回应都偏题。会后复盘时你才发现，真正扣分的不是口音，而是沟通断层。"},{"text":"借口网络不好，静音潜水到底","effects":{"pressure":-4,"health":3,"social":-5,"skill":-2},"narrative":"你把摄像头一关，整场几乎没发言。焦虑暂时下去了，但名字也基本没被任何人记住。"}]}];

export const endingsCatalog = [{"id":"end_dropout_health","priority":200,"title":"休学调整","description":"身体频频亮红灯，你决定先休学一年，把状态找回来。","conditions":{"all":[{"stat":"health","lte":15}]}},{"id":"end_burnout","priority":195,"title":"情绪崩溃","description":"长期高压后你决定先停下来，和自己和解。","conditions":{"all":[{"stat":"pressure","gte":96}]}},{"id":"end_dropout_gpa","priority":190,"title":"学业预警","description":"挂科接连触发学业预警，学分压力把你狠狠拉回现实。","conditions":{"all":[{"stat":"gpa","lte":1.6}]}},{"id":"end_teacher_staff","priority":58,"title":"考编上岸","description":"你把稳定路线走到底，最终拿到编制岗位。","conditions":{"all":[{"flag":"publicInstitutionTrack"},{"stat":"gpa","gte":3},{"stat":"pressure","lte":72}]}},{"id":"end_civil_pass","priority":56,"title":"考公上岸","description":"行测申论刷到手抽筋，终于在公告里看到自己的名字。","conditions":{"all":[{"flag":"civilTrack"},{"stat":"gpa","gte":3},{"stat":"pressure","lte":70}]}},{"id":"end_civil_fail_try_again","priority":55,"title":"考公再战","description":"差一点上岸，但你已经摸清门道，决定来年再冲。","conditions":{"all":[{"flag":"civilTrack"},{"stat":"gpa","gte":2.5}]}},{"id":"end_postgrad","priority":52,"title":"保研路线","description":"成绩和科研都在线，你走上继续深造的路径。","conditions":{"all":[{"flag":"postgradLockedIn"},{"stat":"gpa","gte":3.5},{"stat":"skill","gte":62}]}},{"id":"end_bigtech","priority":39,"title":"大厂 offer","description":"项目和实习都够硬，秋招时你拿到了心仪 offer。","conditions":{"all":[{"stat":"skill","gte":78},{"stat":"gpa","gte":3.4},{"flag":"careerBigTech"}]}},{"id":"end_grad_honors","priority":48,"title":"优秀毕业生","description":"绩点和综合能力都稳定输出，你拿到一份漂亮毕业总结。","conditions":{"all":[{"stat":"gpa","gte":3.7},{"stat":"skill","gte":58}]}},{"id":"end_startup","priority":45,"title":"小队创业","description":"你和同伴把点子做成了 MVP，决定先边做边活下去。","conditions":{"all":[{"stat":"social","gte":60},{"stat":"skill","gte":54},{"flag":"startupIntent"}]}},{"id":"end_romance_stable","priority":42,"title":"恋爱毕业双线通关","description":"你没有把恋爱谈成消耗战，反而学会了边界与支持。","conditions":{"all":[{"flag":"romanceCommitted"},{"stat":"health","gte":45},{"stat":"gpa","gte":2.6}]}},{"id":"end_cert_master","priority":40,"title":"证书收割机","description":"你在证书赛道一路清图，简历像贴满了勋章。","conditions":{"all":[{"flag":"certProgress","gte":2},{"stat":"pressure","lte":84}]}},{"id":"end_grad_normal","priority":10,"title":"普通毕业","description":"你把大学这关稳稳打完，没神话也没崩盘，已经很厉害。","conditions":{"all":[]}},{"id":"end_finance_freedom","priority":49,"title":"财务自由预备役","description":"你在毕业前完成了稳定现金流，钱包先毕业。","conditions":{"all":[{"stat":"money","gte":5200},{"stat":"pressure","lte":68}]}},{"id":"end_research_graduate","priority":47,"title":"科研直博候选","description":"科研轨迹清晰，导师愿意继续带你走更长的路。","conditions":{"all":[{"flag":"researchTrack"},{"flag":"researchProgress","gte":2},{"stat":"skill","gte":72}]}},{"id":"end_city_civil","priority":46,"title":"城市治理新兵","description":"你以稳定心态通过选拔，进入公共治理岗位。","conditions":{"all":[{"flag":"civilTrack"},{"stat":"gpa","gte":3.2},{"stat":"social","gte":55}]}},{"id":"end_teacher_grow","priority":44,"title":"青年教师路线","description":"你找到与人同行的节奏，走上教育行业。","conditions":{"all":[{"flag":"publicInstitutionTrack"},{"stat":"social","gte":60},{"stat":"health","gte":50}]}},{"id":"end_contest_star","priority":43,"title":"竞赛金牌线","description":"比赛与项目沉淀成硬实力，简历含金量拉满。","conditions":{"all":[{"flag":"contestProgress","gte":2},{"stat":"skill","gte":68}]}},{"id":"end_cross_major_success","priority":41,"title":"跨学科逆袭","description":"你在不熟悉的专业语境里打出自己的路径。","conditions":{"all":[{"flag":"crossMajorChallenge"},{"stat":"gpa","gte":3},{"stat":"skill","gte":60}]}},{"id":"end_medical_path","priority":40,"title":"临床继续深造","description":"你走过高压训练，决定继续在医学道路深耕。","conditions":{"all":[{"stat":"skill","gte":66},{"stat":"pressure","lte":88},{"stat":"health","gte":40}]}},{"id":"end_media_operator","priority":39,"title":"内容运营主理人","description":"你把表达与执行能力组合成职业竞争力。","conditions":{"all":[{"stat":"social","gte":72},{"stat":"skill","gte":58},{"stat":"gpa","gte":2.8}]}},{"id":"end_law_practice","priority":38,"title":"法律实务入门","description":"你在规则和现实之间找到了自己的站位。","conditions":{"all":[{"stat":"gpa","gte":3.3},{"stat":"social","gte":58},{"stat":"pressure","lte":78}]}},{"id":"end_small_business","priority":37,"title":"副业经营者","description":"你把校园资源变成了稳定副业，先活得漂亮。","conditions":{"all":[{"stat":"money","gte":4200},{"stat":"social","gte":62}]}},{"id":"end_healthy_graduate","priority":36,"title":"健康优先毕业","description":"你没有在内卷里透支自己，而是稳稳抵达毕业线。","conditions":{"all":[{"stat":"health","gte":78},{"stat":"pressure","lte":52}]}},{"id":"end_lonely_high_score","priority":35,"title":"高分孤岛","description":"成绩很漂亮，但你也付出了社交与生活的代价。","conditions":{"all":[{"stat":"gpa","gte":3.8},{"stat":"social","lte":35}]}},{"id":"end_social_connector","priority":34,"title":"人脉连接者","description":"你成为同学和机会之间的桥梁，路越走越宽。","conditions":{"all":[{"stat":"social","gte":82},{"stat":"pressure","lte":72}]}},{"id":"end_gap_year","priority":33,"title":"间隔年探索","description":"你决定暂缓标准答案，先去看更大的世界。","conditions":{"all":[{"stat":"health","gte":55},{"stat":"money","gte":2600},{"stat":"gpa","lte":2.9}]}},{"id":"end_startup_fail_but_grow","priority":32,"title":"创业受挫但成长","description":"项目没跑通，但你收获了真正的实战能力。","conditions":{"all":[{"flag":"startupIntent"},{"stat":"skill","gte":62},{"stat":"money","lte":1800}]}},{"id":"end_relationship_break","priority":31,"title":"关系失衡","description":"你在关系与节奏间失去平衡，最终选择分开整理自己。","conditions":{"all":[{"flag":"romanceCommitted"},{"stat":"pressure","gte":88}]}},{"id":"end_high_pressure_job","priority":30,"title":"高压入职","description":"你顺利入行，但也把自己推到了极限边缘。","conditions":{"all":[{"flag":"careerBigTech"},{"stat":"skill","gte":64},{"stat":"pressure","gte":82}]}},{"id":"end_cashflow_crisis","priority":29,"title":"现金流危机","description":"资金链持续紧绷，你不得不优先处理生存问题。","conditions":{"all":[{"stat":"money","lte":150},{"stat":"pressure","gte":70}]}},{"id":"end_balanced_allrounder","priority":28,"title":"均衡全能型","description":"你在学业、能力、健康和社交之间维持了漂亮的平衡。","conditions":{"all":[{"stat":"gpa","gte":3.3},{"stat":"skill","gte":63},{"stat":"health","gte":65},{"stat":"social","gte":65},{"stat":"pressure","lte":70}]}},{"id":"end_npc_mentor_postdoc_track","priority":61,"title":"导师盖章的深造线","description":"主导师把你的周报读得像论文摘要，推荐信里写着「抗压与自驱在线」——大厂面试官说你流程感很好，翻译过来就是还行但不是顶尖；而你心里清楚，这条线的门票是无数个凌晨四点的食堂只剩你和打印机的回音。你把寝室夜聊、组会沉默与城市路灯下的自我怀疑都攒成了燃料，终于承认松弛感也需要备案。","epilogue":"五年后你在师兄姐群里转发招聘贴，配文「坑位不多，简历带作品」。点赞里有导师、前任室友与当年的心动对象；你忽然明白成长就是把嘴上的玩笑收成段子，再把段子收成简历里一行「可加班但别把我当耗材」。","conditions":{"all":[{"flag":"primaryMentor"},{"flag":"researchTrack"},{"stat":"skill","gte":73},{"stat":"gpa","gte":3.35}]}},{"id":"end_npc_lovers_dual_city_job","priority":60,"title":"异地恋副本毕业结算","description":"你们把「DDL是第一生产力」这句话异化成「高铁票是第一生产力」：一个在实习楼里写周报，一个在图书馆里刷行测；恋爱没有变成全程消耗战，反而练出了同步日程表与吵架后的复盘会议。小镇做题家在这一刻学会了把浪漫写得像甘特图——难看但管用。","epilogue":"五年后你们在同一个城市合租，冰箱里贴着「本周家务轮值」；朋友说你们像创业公司合伙人，你说合伙人也要写周报，只是周报结尾从「下周计划」改成了「下周约会」。","conditions":{"all":[{"flag":"romanceCommitted"},{"stat":"skill","gte":68},{"stat":"social","gte":58},{"stat":"pressure","lte":76}]}},{"id":"end_npc_startup_couple_mvp","priority":59,"title":"情侣档创业 MVP","description":"路演失败那天你们坐在食堂互相甩锅，第二天又一起改需求文档；「早八刺客」没刺到你们，因为你们把早八献给了产品评审。你们把校园资源、比赛奖金与情绪价值熬成一锅，像同时开恋爱线与公司线，终于理解合伙人的真正含义是「一起背锅也一起分锅」。","epilogue":"五年后公司没上市，但你们学会把生活也当产品迭代；朋友圈发的是小团队团建，评论区有人刷「还招不招对象岗」。","conditions":{"all":[{"flag":"romanceCommitted"},{"flag":"startupIntent"},{"stat":"social","gte":60},{"stat":"skill","gte":56},{"stat":"money","gte":1200}]}},{"id":"end_npc_dorm_treaty_grad","priority":58,"title":"宿舍条约存活者","description":"值日表、熄灯时间、带饭群与「谁再外放谁请全寝奶茶」的君子协定，把寝室从战场升级成能开黑也能开周会的小公司。你在这间十几平米里提前体验了协作、撕逼、和解与团建，毕业照里你们像一支战队——只是装备是插排和收纳箱。","epilogue":"五年后群名还叫「404 宿舍联网成功」，谁结婚谁随份子，谁加班谁发阴阳表情包；你终于相信大学最珍贵的是能一起把日子过成段子的那几个人。","conditions":{"all":[{"flag":"dormProgress","gte":2},{"stat":"health","gte":52},{"stat":"pressure","lte":75}]}},{"id":"end_npc_mentor_civil_branch","priority":57,"title":"导师课题与考公并行线","description":"组会你讲 PPT，晚上你背申论；导师问「你确定不做科研了吗」，你答「我想把城市治理也当系统问题』。像同时开两个存档，压力条经常飘红，但你终于把「稳定」与「被看见」都写进同一条时间线，早八刺客只刺到一次，因为你会用咖啡和错题本反杀。","epilogue":"五年后你在基层写材料，偶尔想起组会上的沉默，觉得那也是一种训练：把复杂问题讲成可执行清单。","conditions":{"all":[{"flag":"primaryMentor"},{"flag":"civilTrack"},{"stat":"gpa","gte":3},{"stat":"pressure","lte":80}]}},{"id":"end_npc_lovers_postgrad_pair","priority":56,"title":"双推免失败但双成长","description":"推免不是唯一答案，但一起准备推免绝对是最像婚姻预演的事：共享焦虑、共享信息差、共享「我完了」和「又活了」。你们没都进梦校，却都进成了更能扛的人；恋爱线没有抢跑绩点，而是把彼此写进同一份未来版本说明里。","epilogue":"五年后一个在读博一个在上班，群聊里仍互丢论文链接与摸鱼转的截图；你们终于懂：势均力敌不是分数一样，是都能把对方从情绪垃圾场里捞回来。","conditions":{"all":[{"flag":"romanceCommitted"},{"flag":"postgradLockedIn"},{"stat":"gpa","gte":3.45},{"stat":"health","gte":48}]}},{"id":"end_npc_off_campus_solo","priority":55,"title":"外宿孤独成长线","description":"你付房租买安静，也买来了独处的全部后果：没有人帮你占座，也没有人在你崩溃时递纸巾。你学会和中介、外卖与凌晨的冰箱对话，把「社恐」活成一种高效。城市路灯下你终于承认，独立不是酷，是贵，但你付得起，因为你要的是能自己掌控的作息与情绪。","epilogue":"五年后你仍喜欢独居，但会主动约饭；你明白孤独是技能树前置，不是终局装备。","conditions":{"all":[{"flag":"offCampus"},{"stat":"gpa","gte":2.9},{"stat":"skill","gte":64},{"stat":"health","gte":50}]}},{"id":"end_npc_cross_major_pivot","priority":54,"title":"转专业之后真香了","description":"冷门课表、陌生同学与「你原来学啥的」社交开场白，让你像穿越进二周目。跨学科逆袭不是说笑，是你真的把不适翻译成了好奇，把补课夜熬成了肌肉记忆。小镇做题家血脉换地图继续刷，只是这次 BOSS 叫自我怀疑。","epilogue":"五年后你在团队里负责「翻译」：把业务语言译成技术语言，把焦虑译成排期；你感谢那次转专业，让你提前适应永远当新手的感觉。","conditions":{"all":[{"flag":"crossMajorChallenge"},{"stat":"gpa","gte":3.05},{"stat":"skill","gte":63},{"stat":"social","gte":50}]}},{"id":"end_npc_senior_angel_project","priority":53,"title":"学长姐天使轮（精神版）","description":"请你喝咖啡的不是暧昧，是行业地图；帮你改简历的不是义务，是传承。你把谢谢说得像打卡，把请教学得像复盘，终于理解「人脉」不是跪出来的，是一起把题做出来后自然结算的掉落物。","epilogue":"五年后你也开始请后辈喝咖啡，发现话术和当年一模一样；你笑着当了一次 NPC。","conditions":{"all":[{"flag":"internshipReady"},{"stat":"social","gte":66},{"stat":"skill","gte":65},{"stat":"money","gte":2000}]}},{"id":"end_npc_romance_skip_academic","priority":52,"title":"跳过恋爱的大四奇迹","description":"你在心动副本点了跳过，把时间梭哈给绩点、证书与实验室；别人在情人节晒花，你在晒合并请求。单身像一种极端专注模式，副作用是偶尔孤独到给路由器改名，但收益是简历终于像样——你把恋爱额度留给毕业后的另一个赛季。","epilogue":"五年后有人问你怎么还不谈，你说「我在等版本更新」；其实你在等自己不再把恋爱当 KPI。","conditions":{"all":[{"flag":"romanceSkipped"},{"stat":"gpa","gte":3.5},{"stat":"skill","gte":70},{"stat":"pressure","lte":78}]}},{"id":"end_npc_midtier_internet","priority":51,"title":"互联网中厂上岸","description":"你没进头部神话组，但进了能写进体检与公积金的那一类；面试官说「我们节奏快但不卷死」，你听出了「会卷但发夜宵」的潜台词。带着恋爱线里练出的情绪管理，你在需求变更里像打太极，把「流程感很好」活成一种生存智慧。","epilogue":"五年后你升了带人，工位上贴着的仍是当年宿舍门牌；你终于懂中厂不是退路，是大多数人真实的生活分辨率。","conditions":{"all":[{"flag":"careerBigTech"},{"stat":"skill","gte":70},{"stat":"gpa","gte":3.1},{"stat":"pressure","lte":85}]}},{"id":"end_npc_bank_teller_pipeline","priority":50,"title":"柜员流水线与体面","description":"你考进系统内基层岗位，穿着制服站在玻璃后面点钞、微笑、忍气吞声；这不是爽文，却是家里饭桌最安心的答案。你把大学练出的「重复劳动耐受」与「微笑营业」全用上，终于理解稳定为什么让人上瘾——因为它让你敢计划下周。","epilogue":"五年后你轮岗到后台，偶尔想起社团路演时的野心；你给自己订了小目标：先把生活过成不失眠再说。","conditions":{"all":[{"flag":"publicInstitutionTrack"},{"stat":"social","gte":54},{"stat":"pressure","lte":72},{"stat":"gpa","gte":2.85}]}},{"id":"end_npc_give_up_civil_retry","priority":49,"title":"弃考一年再战的决心","description":"你在公告前停笔，不是逃，是把自己从「为考而活」里拔出来一年；你去做兼职、去谈一场不功利的恋爱、去把身体从咖啡与焦虑里赎回来。二次进场时你像换了一个存档：题还是那些题，但你不是那个只会刷题的人。","epilogue":"五年后你终于上榜，朋友圈发的是体检合格与食堂第一餐；你评论自己：「弃考不是失败，是重开。」","conditions":{"all":[{"flag":"civilTrack"},{"stat":"health","gte":60},{"stat":"pressure","lte":65},{"stat":"gpa","gte":2.7}]}},{"id":"end_npc_residency_romance","priority":48,"title":"规培压力下的心动残血过关","description":"白大褂、夜班与背不完的重点把生活压成一条细线，而你们还在线里互发「活着吗」；医学规培里那些只有圈内人懂的苦笑，你比谁都熟。你靠睡眠债与彼此提醒撑到毕业，像在高难本里组了固定队，奶与输出都要会。","epilogue":"五年后值夜班的间隙你回消息：「今天也活着」；那是最短的情话，也是最真的战友证词。","conditions":{"all":[{"flag":"romanceCommitted"},{"stat":"skill","gte":65},{"stat":"pressure","lte":90},{"stat":"health","gte":40}]}},{"id":"end_npc_phd_bait","priority":47,"title":"直博诱惑与自我怀疑","description":"导师说「读博吧，平台好」，你看见的是五年后的自己还在改论文。你最终选择先工作再决定，把读博从人生必选项改成可下载 DLC。你学会对光环说「我回去想想」，对焦虑说「先交这周周报」。","epilogue":"五年后你申了在职或再次考研，发现选择没有迟到，只有更清醒的你。","conditions":{"all":[{"flag":"researchTrack"},{"flag":"researchProgress","gte":2},{"stat":"skill","gte":75},{"stat":"pressure","gte":68},{"stat":"gpa","gte":3.2}]}},{"id":"end_npc_home_stay_figuring","priority":46,"title":"家里蹲复习年","description":"你搬回家，把卧室当自习室，把父母关心当环境噪音；你刷题、刷机、刷简历，也在刷自尊。外面世界在前进，你在原地蹲出茧子——但茧子里也长出了规划与边界：你知道什么让你耻辱，什么只是暂时的。","epilogue":"五年后你重新出门，行李少，目标清；你感谢那段蹲，让你学会把面子从进度条里卸载。","conditions":{"all":[{"stat":"money","lte":2200},{"stat":"pressure","lte":62},{"stat":"skill","gte":58},{"stat":"gpa","gte":2.5}]}},{"id":"end_npc_gap_year_visa","priority":45,"title":"出国 Gap 与钱包谈判","description":"你把毕业推迟成一张机票与一堆表格：语言成绩、存款证明与对未来天真的相信。Gap 不是躺，是你主动按下暂停键去换地图；你在异国便利店打工时学会谦卑，也学会把「我语言不好」说得很溜。","epilogue":"五年后你偶尔发旧照片，定位在另一座城；你明白 Gap 年买的不止时间，是重新选择叙事权。","conditions":{"all":[{"stat":"money","gte":4000},{"stat":"health","gte":58},{"stat":"gpa","lte":3.2},{"stat":"social","gte":48}]}},{"id":"end_npc_mentor_letter_item","priority":44,"title":"推荐信与人生道具","description":"你在背包里用过那封推荐信，像用过一次复活币；导师的签名比任何鸡汤都硬。你后来明白道具不是终点，是有人愿意为你背书的证据。你带着它去面试、去申请、去在自我怀疑的夜里翻出来看一遍。","epilogue":"五年后你也开始给后辈写「你很好」的邮件，字少，但重。","conditions":{"all":[{"flag":"mentorUnlocked"},{"stat":"skill","gte":66},{"stat":"gpa","gte":3}]}},{"id":"end_npc_event_chain_master","priority":43,"title":"关系网高密玩家","description":"专属事件像赛季任务一样被你清图：npcEventHits 的计数不是数字，是你在别人故事里刷出的存在感。你终于从「背景板同学」升级成「有台词的 NPC」，也学会在关系里留一点冷却时间给自己。","epilogue":"五年后你仍爱组局，但会提前说「我本周能量低」；边界感是成年人最贵的社交货币。","conditions":{"all":[{"flag":"npcEventHits","gte":9},{"stat":"social","gte":60},{"stat":"health","gte":45}]}},{"id":"end_npc_roommate_break","priority":42,"title":"舍友决裂后的独自强大","description":"最后一次争吵之后你们礼貌地拉黑，像卸载一款占内存太大的软件。你在空下来的寝室里听见自己的心跳，学会自己消化委屈与不公；后来才知道决裂不是失败，是边界毕业的成人礼。","epilogue":"五年后同学聚会你们点头寒暄，像读了一本烂尾小说；你不遗憾，因为你知道自己终于能睡好觉。","conditions":{"all":[{"flag":"dormProgress","gte":1},{"stat":"pressure","gte":78},{"stat":"social","lte":48},{"stat":"gpa","gte":2.4}]}},{"id":"end_npc_lovers_break_clean","priority":41,"title":"体面分手与论文致谢","description":"你们在毕业季把关系卸载得像卸载实验环境：备份回忆，清空权限，祝对方答辩顺利。痛是真的，但你们没有互相写小作文挂树洞；你把这段写进致谢倒数第二段，像给青春一个闭合括号。","epilogue":"五年后你在婚礼请柬名单上犹豫三秒，最后只点赞；成熟是把遗憾折叠成一句「都挺好」。","conditions":{"all":[{"flag":"romanceCommitted"},{"stat":"pressure","gte":80},{"stat":"pressure","lte":87},{"stat":"gpa","gte":2.8},{"stat":"health","gte":42}]}},{"id":"end_npc_intern_bigcity_rent","priority":40,"title":"大城实习租房渡劫","description":"押一付三、地铁通勤与合租房里的陌生呼吸，让你提前体验「社会人」的物理意义。你在实习与生存之间走钢丝，把「流程感」练成「生活感」；工资一半给房东，一半给未来，剩一点给周末的火锅自愈。","epilogue":"五年后你买房仍远，但敢谈「我想留下」；这一步你已经赢了当年的自己。","conditions":{"all":[{"flag":"internshipReady"},{"stat":"money","lte":3200},{"stat":"skill","gte":66},{"stat":"pressure","lte":82}]}},{"id":"end_npc_contest_to_job","priority":39,"title":"竞赛奖状换门票","description":"奖牌不是终点，是面试官愿意多听你说两句的理由；你在答辩场上讲算法像在讲青春。你把队友处成战友，把熬夜处成共同遗产，终于明白赢一次不是为了炫耀，是为了相信自己还能赢下一次。","epilogue":"五年后奖项落了灰，但「我们能做出来」的底气还在工位上发光。","conditions":{"all":[{"flag":"contestProgress","gte":2},{"stat":"skill","gte":72},{"stat":"gpa","gte":2.9}]}},{"id":"end_npc_cert_wall","priority":38,"title":"证书墙就业通道","description":"你把墙面贴得像违章建筑，但 HR 认其中几张；考证不是爱好，是小镇做题家切换到大城市货币体系的汇率兑换。你在格子间与考场之间复制粘贴耐心，终于换到一张「你可以进来」的纸条。","epilogue":"五年后你劝后辈少考两张没用的，但心里偷偷骄傲：当年那张最难考。","conditions":{"all":[{"flag":"certProgress","gte":2},{"stat":"pressure","lte":86},{"stat":"gpa","gte":2.85}]}},{"id":"end_npc_finance_side_hustle","priority":37,"title":"理财与小生意并行","description":"基金曲线像心电图，副业订单像随机掉落；你在风险与收益之间练习成年人的算术。没有暴富神话，只有每月对账时的踏实；你终于理解自由不是潇洒，是多一点选择的余地。","epilogue":"五年后你仍定投，但标的换成健康与家人；回报不以百分比写，以睡得着写。","conditions":{"all":[{"flag":"financeProgress","gte":2},{"stat":"money","gte":3600},{"stat":"pressure","lte":74}]}},{"id":"end_npc_volunteer_teacher_path","priority":36,"title":"支教志愿者转教师梦","description":"讲台上的十分钟像一辈子那么长，孩子们的笑声却一秒把你治愈。你把公益实践读成职业预言书，把「我能改变什么」从宏大叙事缩小到一张作业本上的红勾。","epilogue":"五年后你在山区或城里都在讲课，身份不同，心跳一样。","conditions":{"all":[{"flag":"studentWork","gte":2},{"stat":"social","gte":62},{"stat":"health","gte":50}]}},{"id":"end_npc_study_abroad_wait","priority":35,"title":"先工作再留学的折中","description":"你把留学从直线改成折线：先攒经验与存款，再换地图。别人问你怎么不干脆点，你说「我想带着问题去读」，而不是带着空白去接受答案。","epilogue":"五年后你起飞那天行李超重，心里不重；你知道这笔 Gap 自己买单，也更值得。","conditions":{"all":[{"stat":"money","gte":4800},{"stat":"skill","gte":68},{"stat":"gpa","gte":3.05},{"stat":"pressure","lte":75}]}},{"id":"end_npc_health_first_runner","priority":34,"title":"健康优先的慢跑哲学家","description":"你把跑步写进课表比把课写进课表还真；体检指标回升的那天，你比拿奖学金还激动。内卷里你选择保命流打法，用睡眠与有氧对抗虚无；别人说你不拼，你说你只是不想拼进急诊。","epilogue":"五年后你仍跑步，配速慢了，但人生长了；这才是持久战的姿势。","conditions":{"all":[{"stat":"health","gte":80},{"stat":"pressure","lte":48},{"stat":"gpa","gte":2.75}]}},{"id":"end_npc_night_owl_redemption","priority":33,"title":"夜猫子改作息成功","description":"你曾经把凌晨当成生产力，后来把凌晨还给睡眠；过程像戒断，梦里全是未提交的作业。你终于承认身体不是可透支额度，早八刺客其实是生物钟在报复。","epilogue":"五年后你仍会熬夜，但是有意识地熬；可控的堕落才算浪漫。","conditions":{"all":[{"stat":"health","gte":62},{"stat":"pressure","lte":58},{"stat":"skill","gte":60}]}},{"id":"end_npc_item_pack_rat","priority":32,"title":"背包道具流通关","description":"你用物品与道具把随机事件变成可控增益：咖啡、眼罩、推荐信与不知名的提神糖，像 RPG 里叠 buff。别人笑你装备党，你笑他们裸奔进期末。","epilogue":"五年后你办公桌抽屉仍像百宝箱；人生啊，有时候就是叠满 buff 再上场。","conditions":{"all":[{"flag":"itemUsage","gte":3},{"stat":"gpa","gte":2.8},{"stat":"money","gte":1500}]}},{"id":"end_npc_social_butterfly_engineer","priority":31,"title":"社牛工程师上岸","description":"你能同时在五个群里活跃并且把项目推进——社交不是分散注意力，是你独特的并行架构。你把人脉编译成机会，把段子编译成信任，终于理解「会做人」也是硬核技能。","epilogue":"五年后带团队才发现，最难的不是技术，是让每个人都觉得自己被看见。","conditions":{"all":[{"stat":"social","gte":78},{"stat":"skill","gte":66},{"stat":"gpa","gte":2.95}]}},{"id":"end_npc_lonely_grinder_love_late","priority":30,"title":"高分孤岛后来信","description":"绩点像城墙，你在上面看风景也看别人牵手；后来心动来时你已学会慢热，像把自己从孤岛上摆渡回人间。你不再用分数证明 worth，改用真诚练习亲密。","epilogue":"五年后你仍会加班，但有人留灯；那盏灯比任何排名更让你想哭。","conditions":{"all":[{"stat":"gpa","gte":3.75},{"stat":"social","lte":42},{"stat":"skill","gte":72}]}},{"id":"end_npc_civil_progress_carry","priority":29,"title":"考公里程碑堆积","description":"你把错题与申论段落堆成一座小山，像在游戏里刷日常；公告推迟你推迟焦虑，成绩公布你学会把希望调低一格再接受结果。稳定路线不是浪漫，是耐力赛。","epilogue":"五年后你路过考点仍会心悸；那不是创伤，是青春的回响。","conditions":{"all":[{"flag":"civilTrack"},{"flag":"civilProgress","gte":2},{"stat":"gpa","gte":2.65}]}},{"id":"end_npc_research_quit_industry","priority":28,"title":"科研退坑转工程","description":"你在实验室耗尽了浪漫，决定把浪漫换成工资；不是背叛，是认清自己更爱交付而不是假设。你带着读论文练出的耐心去写需求文档，居然如鱼得水。","epilogue":"五年后带项目你仍会引用论文一句结论；那是你与科研线的和解脚注。","conditions":{"all":[{"flag":"researchTrack"},{"stat":"skill","gte":69},{"stat":"pressure","gte":72},{"flag":"internshipReady"}]}},{"id":"end_npc_startup_mentor_bridge","priority":27,"title":"导师资源嫁接创业","description":"导师一句「可以试着落地」比一百节创业课有用；你把课题组边角料课题做成小产品，像把论文翻译成人民币。学术与商业之间不是悬崖，是窄桥，你扶着栏杆过去了。","epilogue":"五年后公司半死不活，但你学会了把失败写成下一版的更新日志。","conditions":{"all":[{"flag":"primaryMentor"},{"flag":"startupIntent"},{"stat":"social","gte":57},{"stat":"skill","gte":58}]}},{"id":"end_npc_romance_library_endgame","priority":26,"title":"图书馆牵手线完结篇","description":"你们在闭馆音乐里收拾书包，像收拾四年；情侣座位从不张扬，却在索引里写下彼此的偏好。毕业不是剧终，是你们终于敢把「以后」说成「下周见」。","epilogue":"五年后你们仍抢自习座位，只是抢的是家里的书桌；闭馆音乐换成了电饭煲提示音，也一样温柔。","conditions":{"all":[{"flag":"romanceCommitted"},{"stat":"gpa","gte":3.15},{"stat":"pressure","lte":72},{"stat":"social","gte":55}]}},{"id":"end_love_grad_together","priority":27,"title":"恋人与毕业证同一批到货","description":"毕业照里你们站得很近，像把四年里没说完的甜都压进一帧。朋友调侃你们像「官方周边」，你笑着把话头接住，心里却认真：能一起把恋爱谈过论文与租房合同，比任何校园剧都难演。招聘季你们互相改简历、互相撑过面试凉经，把「我们」写进了各自的城市选择里。随手截图可以丢进相册，但一起扛过的焦虑与期待，只可能写进人生。","epilogue":"五年后你们仍习惯共享日历与番茄钟，偶尔吵到想分房，最后分的是谁去扔垃圾。","conditions":{"all":[{"flag":"romanceCommitted"},{"stat":"social","gte":58},{"stat":"gpa","gte":2.7},{"stat":"health","gte":40}]}},{"id":"end_mentor_recommend","priority":27,"title":"导师递来的那张纸","description":"主导师在组会散场后叫住你，把推荐信封好递过来，像把一条隐形的线系在你和下一程之间。你想起那些熬夜补的图、被批注到体无完肤的摘要，以及某次组会后他请你喝的那杯并不好喝的速溶。秋招或保研材料的文件夹里，这封信比别人家的段子更早把你送进下一轮；别人说贵人相助，你更愿意相信是长期交付换到的「流程感很好」之外的那一点真。「导师是第一生产力」终于从一句口头禅，变成了可执行文件。","epilogue":"五年后你在行业群里看到导师转发顶会链接，顺手点了个赞，彼此都没说话。","conditions":{"all":[{"flag":"primaryMentor"},{"stat":"skill","gte":68},{"stat":"gpa","gte":3.1}]}},{"id":"end_roommate_founders","priority":26,"title":"寝室三人组创业试水","description":"你们把宿舍夜谈里的点子搬进了工商注册表，股权比例吵得像分锅包肉。路演被怼、合同踩坑、供应链翻车，你们一边互损一边改需求；DDL是第一生产力，凌晨四点的食堂只剩你们和阿姨的拖把。第一笔到账不大，但足够请客吃完那一顿「还没倒闭」的火锅。后来你们明白：合伙人不一定要志同道合，至少要一起扛过甲方与期末。","epilogue":"五年后公司还在，名字土但活着；群名仍是「再改需求就退群」。","conditions":{"all":[{"flag":"startupIntent"},{"stat":"social","gte":55},{"stat":"skill","gte":56},{"stat":"money","gte":1200}]}},{"id":"end_transfer_hero","priority":26,"title":"转专业后的窄门","description":"跨专业像把操作系统重装：课表、黑话、社交圈全换。你补修到怀疑人生，却在某次大作业里突然「编译通过」——原来不熟悉的坐标系里也能跑通自己的路。绩点起起落落像心电图，但你知道自己在对的赛道上加杠杆；小镇做题家在此刻升级成「小镇迁移工程师」。别人问你怎么敢转，你说再不转就要把一辈子卖给不喜欢的主角脚本。","epilogue":"五年后你在新领域里带实习生，第一句话永远是：先别慌，补修我也挂过。","conditions":{"all":[{"flag":"crossMajorChallenge"},{"stat":"gpa","gte":3},{"stat":"skill","gte":58}]}},{"id":"end_gap_world","priority":25,"title":"Gap 一年去看海与报错","description":"你暂缓「标准答案」，用间隔年换护照上的章与简历上的空白。打工、义工、穷游与自学搅在一起，像同时开十个线程；父母电话里的沉默比唠叨更响，你却学会了把焦虑写成待办而不是愧疚。你意识到人生不是秋招列表，允许一条分支编译失败再重跑。早八刺客暂时失联，但你对时间的体感反而更锋利。","epilogue":"五年后你仍会在加班夜想起那段没钱却阔的日子，像想起一段开源项目的狂热期。","conditions":{"all":[{"stat":"health","gte":52},{"stat":"money","gte":2200},{"stat":"gpa","lte":3.05},{"stat":"gpa","gte":2.3}]}},{"id":"end_neet_soft","priority":24,"title":"家里蹲备案中","description":"毕业后你先把自己关机重启：投递断断续续，出门需要心理建设，外卖软件比你更懂你的作息。爸妈把关心伪装成唠叨，你把自嘲伪装成松弛感，夜里刷到同龄人高光时仍会心绞痛。你知道这不是终局，只是存档点；先把睡眠与肠胃修好，也是一种硬核运维。表情包救不了房租，但能让你明天还能点开招聘软件。","epilogue":"五年后你终于对别人轻描淡写提起那段「空白」，像提起一次漫长的系统维护。","conditions":{"all":[{"stat":"money","lte":900},{"stat":"gpa","lte":2.5},{"stat":"pressure","lte":62}]}},{"id":"end_mid_internet","priority":25,"title":"互联网中厂合格证","description":"你没有拿到传说中年包百万的「顶配岗」，但中厂的作息与需求变更把你打磨成可上线版本。面试官说你有流程感，你翻译：知道怎么在评审里活着把需求做完。团建像大型破冰 DLC，工位像第二个寝室；你学会了用周报把琐碎包装成资产。小镇做题家在此进化成「小镇交付工程师」。","epilogue":"五年后你跳槽时才发现，那年学会的甩锅与对齐才是硬通货。","conditions":{"all":[{"flag":"internshipReady"},{"stat":"skill","gte":64},{"stat":"skill","lte":76},{"stat":"gpa","gte":2.9}]}},{"id":"end_bank_counter","priority":24,"title":"玻璃后面的柜员线","description":"你考上编制边缘岗位，穿上制服坐在防弹玻璃后，点钞与微笑都有 KPI。客户把焦虑砸在你脸上，你把流程背成肌肉记忆；钞箱沉重，午休很短，但公积金按时到账像温柔补丁。同学说埋没才华，你说先把生活编译通过。早八刺客在此变为晨会刺客，迟到一分钟全网点都知道。","epilogue":"五年后你轮岗到后台风控，终于不用微笑面对无理取闹，只需面对 Excel。","conditions":{"all":[{"flag":"publicInstitutionTrack"},{"stat":"gpa","gte":2.6},{"stat":"gpa","lte":3.2},{"stat":"social","gte":45}]}},{"id":"end_med_intern_crash","priority":26,"title":"规培夜班崩溃文学","description":"医学路径把你送进医院迷宫：查房、病程、夜班与情绪劳动无限循环。你在值班室写过检讨也写过遗书草稿，最后只发出一条「还活着」给家人。带教骂你与鼓励你同一套声带；你学会在崩溃边缘写交接班，像把人生切成可交接的班次。DDL 在此变成「生命体征要先稳住」。","epilogue":"五年后你仍会做噩梦梦见医嘱签晚了一分钟，醒来发现自己已经能边噩梦边入睡。","conditions":{"all":[{"stat":"skill","gte":62},{"stat":"pressure","gte":78},{"stat":"health","lte":48}]}},{"id":"end_phd_slow_track","priority":25,"title":"读博慢车道入口","description":"导师与你长谈三次，终于在你简历与论文间隙里敲下「建议深造」。你知道博士不是光环，是更长线的延迟满足；实验失败像无限 while，只有你改的 bug 能看见出口。恋爱对象问你还要读几年，你只能说「取决于审稿人心情」。卷王在此升级为「卷五年预览版」。","epilogue":"五年后你发际线后移但眼神更稳，终于敢自嘲「实验室常住人口」。","conditions":{"all":[{"flag":"researchTrack"},{"flag":"researchProgress","gte":2},{"stat":"gpa","gte":3.2},{"stat":"skill","gte":70}]}},{"id":"end_senior_startup_pair","priority":25,"title":"学姐合伙练摊","description":"学长学姐不是传说，是把你拉进小项目的真实甲方兼合伙人。你们分摊焦虑与发票，校门口摆摊与线上测评双线并行，熬夜做出第一份用户反馈表。失败很快，迭代更快；你们互相吐槽「小镇做题家只会做题」，转头却把表格做成护城河。那些合伙人口嗨在此落地成报销单与合伙人协议。","epilogue":"五年后公司未必还在，但你们的微信群仍是彼此的避险资产。","conditions":{"all":[{"flag":"startupIntent"},{"stat":"social","gte":62},{"stat":"money","lte":3200}]}},{"id":"end_romance_split_city","priority":24,"title":"恋人分隔两座城","description":"你们把毕业做成选择题 rather than 判断题：offer 在不同经纬度，爱与前途互相拉扯。视频里说的「马上见」越来越像接口超时重试。结局未必狗血，可能只是在车站抱着哭完，然后各自去安检口排队。你学会把想念写成周报式的碎碎念，截图存进相册，现实写进离别教程。","epilogue":"五年后偶然同城出差约饭，彼此客气得像外包对接。","conditions":{"all":[{"flag":"romanceCommitted"},{"stat":"pressure","gte":72},{"stat":"social","lte":52}]}},{"id":"end_dorm_rift","priority":24,"title":"舍友决裂冷却期","description":"最后一次争吵不是因为卫生，是因为彼此的未来想象互相刺痛。群聊沉默，值日表失效，耳机成为外交边界；你在走廊听见他们笑，像你从未加入过的副本。你学会把情绪卸载到跑步与日记里，而不是卸载到学业上。寝室政治教会你的不是心机，是何时该搬出去。","epilogue":"五年后同学聚会你们礼貌点头，像承认一段旧版本兼容失败。","conditions":{"all":[{"stat":"pressure","gte":82},{"stat":"social","lte":42},{"stat":"gpa","gte":2.4}]}},{"id":"end_overseas_language","priority":25,"title":"出国预备役口语班","description":"你把雅思托福与 GRE 当成新一卡通：打卡、模考、复议与崩溃循环。签证材料厚得像毕设，面试官问你「为什么出国」，你说想换个服务器跑人生。父母赞助与你的倔强混合成保证金；朋友圈晒 offer 那天，你也晒了一碗泡面。Gap 在此不是躺平，是排队读语言的漫长前置。","epilogue":"五年后你在时区另一头熬夜加班，终于懂得什么叫「换了服务器延迟还在」。","conditions":{"all":[{"stat":"skill","gte":72},{"stat":"money","gte":3500},{"stat":"gpa","gte":3}]}},{"id":"end_civil_retry_parent","priority":23,"title":"考编弃考再战协定","description":"报名费和沉没成本在桌面开会：这次没去考场，因为你知道只是逃避型到场。父母叹气又给你盛饭，你把羞愧嚼碎咽下，改成来年再战的学习计划。申论素材库里多了「与现实和解」这一章。别人说你是逃兵，你对自己说这是战术撤退。","epilogue":"五年后你上岸那天，最先想到的是那年弃考的午后阳光。","conditions":{"all":[{"flag":"civilTrack"},{"stat":"gpa","gte":2.4},{"stat":"pressure","gte":65},{"stat":"pressure","lte":88}]}},{"id":"end_teach_rural","priority":24,"title":"支教合同上的签名","description":"你去乡镇学校报到那天，行李箱轮子卡在雨后泥里。孩子们喊你老师，你把大城市焦虑暂时静音；教案写到深夜，蚊子比学生更难缠。工资不高，但某种意义感像补贴一样按月打到心里。小镇做题家回流小镇当老师，像故事线自己画了一个圈。","epilogue":"五年后你考回城里编制，仍会给新生讲那段晒脱皮的日子。","conditions":{"all":[{"flag":"publicInstitutionTrack"},{"stat":"social","gte":52},{"stat":"health","gte":48}]}},{"id":"end_offcampus_lonely","priority":23,"title":"外宿独居噪声","description":"租房合同是你的第一份「完整独立 DLC」：水电、隔音与通勤成本教你做人。夜里路灯像延迟加载的贴图，外卖骑手是你见得最多的熟人。社交变少，专注变多；孤独像白噪声，习惯后反而好睡。你说自由很贵，但闹钟终于只属于自己。","epilogue":"五年后你买房首付仍远，但早已不怕一个人吃火锅。","conditions":{"all":[{"flag":"offCampus"},{"stat":"gpa","gte":2.8},{"stat":"social","lte":48}]}},{"id":"end_family_business","priority":23,"title":"回家接班试探版","description":"家里的小生意在饭桌上摊开：叫你回去帮忙、考证、接班。你在 spreadsheet 与亲情之间走钢丝，既不想辜负也不想轻易投降。周末蹲店里学会了把面子换成现金流。聊天里那张「继承家业」的截图，落地成扫码枪与进货单。","epilogue":"五年后店还在，你头发少了，但爸妈语气软了。","conditions":{"all":[{"stat":"money","lte":2000},{"stat":"social","gte":48},{"stat":"gpa","lte":3}]}},{"id":"end_freelance_creator","priority":24,"title":"自由职业试水号","description":"你接单、拖稿、改稿、追款，把简历写成作品集又把作品集拆成单篇报价。客户说「预算不多但要高级感」，你微笑打开模板文件夹。收入起伏像比特币表情包，但时间主权是真的。父母问你五险一金，你只好转发一篇科普。","epilogue":"五年后你有了固定客户与房贷，仍保留离职冲动的备份存档。","conditions":{"all":[{"stat":"social","gte":60},{"stat":"skill","gte":60},{"stat":"money","gte":2800},{"stat":"money","lte":5000}]}},{"id":"end_public_inspector","priority":23,"title":"基层巡查笔录员","description":"你穿着工装走过片区：表格、整改、复查与群众投诉构成日常。雨靴比球鞋更常穿，微信步数是你唯一能卷的排行榜。稳定不是躺平，是把琐碎砌成秩序。考公路线在此分叉成街道办事处的另一种亮度。","epilogue":"五年后你升科长那天，仍记得第一次被居民骂哭的雨夜。","conditions":{"all":[{"flag":"civilTrack"},{"stat":"social","gte":50},{"stat":"gpa","gte":2.7},{"stat":"gpa","lte":3.3}]}},{"id":"end_design_studio","priority":23,"title":"乙方美工求生","description":"你在工作室里改第 N 版「还是要第一版」，色域与血压同步飙升。甲方说「大气」，你翻译：再大一点再空一点再便宜一点。作品集越来越厚，头发越来越薄。DDL 是第一生产力，你更像第一生产力的耗材。","epilogue":"五年后你跳槽甲方第一件事就是善待乙方，像善待当年的自己。","conditions":{"all":[{"stat":"skill","gte":58},{"stat":"pressure","gte":68},{"stat":"gpa","gte":2.6}]}},{"id":"end_data_analyst","priority":24,"title":"表格战士初级职称","description":"SQL 与 Excel 成为你的左右护法；汇报会上你把图表做成故事线，老板点头像稀有掉落。你不知道算不算热爱，但至少周五晚上不用睡机房。「流程感很好」在此翻译成：指标能对齐。小镇做题家升级成小镇透视表工程师。","epilogue":"五年后你带新人第一句：先别炫技，把口径对齐。","conditions":{"all":[{"stat":"skill","gte":66},{"stat":"gpa","gte":3},{"stat":"pressure","lte":75}]}},{"id":"end_sales_engineer","priority":23,"title":"售前工程师嘴炮岗","description":"你一半时间在客户现场画架构，一半时间在内部撕资源；PPT 与 demo 环境是你的左右互搏。懂技术又懂画饼的人，在饭局与复盘会之间反复横跳。社交拉满不是天赋，是工单。","epilogue":"五年后你说话变慢了，因为知道每句都可能进会议纪要。","conditions":{"all":[{"stat":"social","gte":70},{"stat":"skill","gte":60},{"stat":"gpa","gte":2.5}]}},{"id":"end_journalism_intern","priority":22,"title":"媒体实习跑现场","description":"你扛着脚架跑突发，也写过没人看的转载稿；前辈说新闻理想很贵，你先把饭票挣到手。凌晨热线像随机事件池，你在稿库里练习把残酷写得克制。早八刺客换成了凌晨三点的突发推送。","epilogue":"五年后你转行公关，仍会对热搜条件反射。","conditions":{"all":[{"stat":"social","gte":56},{"stat":"pressure","gte":62},{"stat":"health","gte":42}]}},{"id":"end_nonprofit_ops","priority":22,"title":"公益机构项目官","description":"筹款、审计、活动与志愿者管理填满日程；工资不高，会议纪要很长。你在琐碎里看见具体的人，而不是宏大叙事。成就感来自项目结项那天家长的短信，而不是转发量。佛系在此不是躺，是把力气用在对的地方。","epilogue":"五年后你跳槽企业 CSR，工资翻倍但偶尔想念前线。","conditions":{"all":[{"stat":"social","gte":54},{"stat":"skill","gte":52},{"stat":"money","lte":3800}]}},{"id":"end_game_industry","priority":23,"title":"策划案与氪金逻辑","description":"你进了游戏公司做系统策划，天天与数值、活动表与玩家骂声共处。策划会上老板要「既有深度又要轻度」，你沉默打开竞品拆解。热爱变工单仍值得庆幸：至少夜班能报销打车。你在游戏里藏彩蛋，在现实里藏睡眠。","epilogue":"五年后你玩自家游戏会跳过氪金点，像避开年轻时的坑。","conditions":{"all":[{"stat":"skill","gte":64},{"stat":"social","gte":50},{"stat":"pressure","gte":60}]}},{"id":"end_supply_chain","priority":22,"title":"供应链跟单员长途","description":"电话、合同、船期与报关单是你微信置顶；时差让你学会把失眠卖给咖啡机。你在车间与港口之间学会谦卑：世界很大，表格很小。搞钱在此不是暴富，是回款准时。","epilogue":"五年后你升职经理，仍会对延误有 PTSD。","conditions":{"all":[{"stat":"money","gte":3600},{"stat":"skill","gte":54},{"stat":"social","gte":46}]}},{"id":"end_critic_reader","priority":21,"title":"出版业板凳队员","description":"你在出版社做编辑助理，拆快递、对清样、追作者拖稿；书的油墨味比 KPI 好闻。理想主义被印厂工期磨薄，但你仍会在某本书的首印夜偷偷发朋友圈。小镇做题家在此变成小镇校对员。","epilogue":"五年后你笔名出书，扉页致谢写了那段板凳年份。","conditions":{"all":[{"stat":"gpa","gte":3},{"stat":"pressure","lte":58},{"stat":"skill","gte":55}]}},{"id":"end_gym_coach","priority":21,"title":"健身房储备教练","description":"考证、试课、卖课与维持体脂构成你的三角循环；镜子里的你与会员眼里的你是两份 KPI。你把自律当成职业，也当成枷锁；汗水是真的，鸡汤也是真的。养生在此等于肌肉酸痛管理。","epilogue":"五年后你开小店当老板，终于可以对推销话术免疫。","conditions":{"all":[{"stat":"health","gte":72},{"stat":"social","gte":58},{"stat":"skill","gte":50}]}},{"id":"end_logistics_hub","priority":21,"title":"仓储夜班调度","description":"扫码枪是你的魔杖，干线晚点是你的随机事件；你与骑手、司机、客服共建微信群宇宙。身体疲惫，但现金流真实；你说先攒钱再谈职业规划这种老实话。早八刺客输给了凌晨三点的分拣线。","epilogue":"五年后你转行产品经理，因为受够了「系统里明明不是这么写的」。","conditions":{"all":[{"stat":"money","gte":3200},{"stat":"health","lte":62},{"stat":"pressure","gte":58}]}},{"id":"end_coffee_chain","priority":21,"title":"连锁咖啡储备店长","description":"配方表、盘点与客诉把你训练成微笑机器；高峰期像黑客松，你在奶泡与订单号之间修行。学历像闲置技能点，但你不瞧不起此刻——先把房租稳住。搞钱线的烟火气在此等于蒸汽棒嘶嘶声。","epilogue":"五年后你自己开店，菜单仍写着当年练手的隐藏款。","conditions":{"all":[{"stat":"social","gte":52},{"stat":"money","gte":2600},{"stat":"gpa","lte":2.9}]}},{"id":"end_realty_agent","priority":21,"title":"房产中介带看王者","description":"你记住片区每一套采光与房东脾气；客户说要再看看，你笑着预约下一套。嘴皮子与脚程是你的复合技能；签约那刻的快感堪比答辩通过。社交在此等于合法骚扰与真诚并存。","epilogue":"五年后你只做豪宅渠道，仍会对雨伞常备两件。","conditions":{"all":[{"stat":"social","gte":68},{"stat":"money","gte":3000},{"stat":"skill","gte":48}]}},{"id":"end_farm_tech","priority":22,"title":"农技推广员下乡记","description":"你把传感器与无人机介绍给合作社；老乡问你英语六级能不能防虫害，你只能苦笑科普。科研在此接地：泥土与数据表同样沉重。农业创新不是嘴上热搜，是耐心比键盘长。","epilogue":"五年后试点扩大，你却在ppt里放了一张第一年失败的苗。","conditions":{"all":[{"stat":"skill","gte":58},{"stat":"health","gte":55},{"stat":"social","gte":48}]}},{"id":"end_secret_crush","priority":22,"title":"暗恋停在致谢里","description":"你没有把喜欢说出口，只在毕业典礼合影里站得离 TA 近一点。后来朋友圈点赞成为你唯一的交互协议。遗憾是真的，自由也是真的：你把心动兑换成一场不被打分的关系。暧昧三连击一场都没触发，但你学会了克制也算成长。","epilogue":"五年后同学会你们寒暄，像彼此早已卸载的客户端。","conditions":{"all":[{"flag":"romanceSkipped"},{"stat":"gpa","gte":3},{"stat":"social","lte":45}]}},{"id":"end_parent_expect","priority":22,"title":"父母的默认路径","description":"你沿着家人期待的公式投递：本地、稳定、可相亲。内心的小反抗只在深夜耳机里播放。你知道这不是史诗，只是中国式温情与控制的混合包。你在表格里填「服从调剂」，像对自己人生也按下默认安装。","epilogue":"五年后你开始偷偷接副业，像给默认路径打补丁。","conditions":{"all":[{"stat":"pressure","gte":60},{"stat":"social","lte":50},{"stat":"gpa","gte":2.7},{"stat":"gpa","lte":3.2}]}},{"id":"end_double_degree","priority":23,"title":"双学位缝合怪","description":"你同时啃两套培养方案，考试周像叠 debuff；室友以为你分身，其实你只是咖啡耐受提高。简历多一行，头发少一撮；但跨界想象力从此合法。卷王在此表现为「双倍培养方案生存实验」。","epilogue":"五年后你做交叉岗位反而吃香，因为早就习惯翻译两种黑话。","conditions":{"all":[{"stat":"gpa","gte":3.1},{"stat":"pressure","gte":70},{"stat":"skill","gte":62}]}},{"id":"end_volunteer_legacy","priority":21,"title":"大型赛会志愿者遗产","description":"你攒下一沓志愿者证书与晒黑的皮肤；见过凌晨四点的场馆与媒体村的泡面。志愿时长换不了首付，却换来一群同类朋友与可控的热血。社牛在此是被 workflow 训练出来的。","epilogue":"五年后城市办赛你第一反应仍是：我去不去守门？","conditions":{"all":[{"stat":"social","gte":60},{"stat":"health","gte":50},{"stat":"skill","gte":50}]}},{"id":"end_debt_student","priority":22,"title":"助学贷款偿还长跑","description":"毕业第一件事是把还款日历钉在桌面；工资到手先拆成几份，像拆解炸弹。你羡慕别人的松弛感，却也尊敬自己的信用记录。搞钱在此不是欲望，是义务函数最小化。","epilogue":"五年后你还清那天请自己吃了顿贵的，发票撕得比毕业证还爽。","conditions":{"all":[{"stat":"money","lte":2200},{"stat":"skill","gte":55},{"stat":"pressure","gte":55}]}},{"id":"end_night_school","priority":20,"title":"夜校证书叠 Buff","description":"白天上班晚上上课，你在地铁里背单词像挂机刷怪；困到在最后一排点头，但仍抢到前排插座。你知道证书不是魔法，但能给简历多一行确定性。DDL 是第一生产力，夜校就像给这条定律办分期。","epilogue":"五年后证堆满抽屉，你最珍惜的是那段不肯躺平的劲儿。","conditions":{"all":[{"flag":"certProgress","gte":1},{"stat":"pressure","gte":62},{"stat":"money","lte":4000}]}},{"id":"end_clinic_admin","priority":21,"title":"医院行政岗稳稳幸福","description":"你不拿手术刀，却负责让手术排期不乱；投诉电话像随机事件，你用流程表接住情绪。稳定、体面、偶尔心累；你在「幕后运维」里找到位置。考编 wins 的一种低温版本。","epilogue":"五年后临床同学羡慕你不值班，你羡慕他们不被投诉。","conditions":{"all":[{"flag":"publicInstitutionTrack"},{"stat":"pressure","lte":68},{"stat":"gpa","gte":2.5},{"stat":"gpa","lte":3.1}]}},{"id":"end_tech_support","priority":20,"title":"IT 运维值班魂","description":"7x24 热线是你的人生节拍器；故障单像无限刷新的支线。你学会在骂声中保持 ping 通。技能点偏硬，脾气被迫变软；凌晨告警比闹钟更懂你的作息。高压入职的低温对照组。","epilogue":"五年后你转架构岗，终于能把电话转给下一班兄弟。","conditions":{"all":[{"stat":"skill","gte":60},{"stat":"pressure","gte":72},{"stat":"health","gte":45}]}},{"id":"end_cultural_heritage","priority":20,"title":"文博策展助理","description":"你在展馆与库房之间搬运时间与灰尘；讲解词背到梦里。游客自拍比你想象的更重要，你也学会与流量共存。专业在此落地成灯光角度与展线逻辑。佛系不是懒，是对文物轻声说话。","epilogue":"五年后你独立策展，序言里藏了大四时拖场的自己。","conditions":{"all":[{"stat":"gpa","gte":2.8},{"stat":"social","gte":48},{"stat":"pressure","lte":65}]}},{"id":"end_ws_mock","priority":19,"title":"平行日常 · 留白的你","description":"你没有触发宏大叙事，却把每一天过得可复盘：食堂、教室、寝室三点循环里仍有细小骄傲。朋友说你不像主角，你反驳主角也要有人演路人甲的自我修养。普通毕业在此前的万千分支之后，仍值得一杯奶茶庆祝。","epilogue":"五年后你把这段岁月当成默认皮肤，偶尔换上野心主题试试。","conditions":{"all":[{"stat":"gpa","gte":2.5},{"stat":"social","gte":38},{"stat":"social","lte":62}]}}];

